    fn import_agent_browser_final_validation_result_from_clipboard(
        &mut self,
        cx: &mut Context<Self>,
    ) {
        let Some(clipboard_text) = cx.read_from_clipboard().and_then(|item| item.text()) else {
            self.show_toast(
                "No clipboard text available for final validation result import",
                cx,
            );
            return;
        };
        let Ok(value) = serde_json::from_str::<Value>(&clipboard_text) else {
            self.show_toast("Clipboard does not contain valid final validation JSON", cx);
            return;
        };
        let result = value
            .get("manual_evidence_template")
            .cloned()
            .unwrap_or(value);
        if result.pointer("/schema").and_then(Value::as_str)
            != Some(AGENT_BROWSER_FINAL_VALIDATION_RESULT_SCHEMA)
        {
            self.show_toast("Clipboard final validation JSON has the wrong schema", cx);
            return;
        }
        let summary = Self::agent_browser_final_validation_result_summary(&result);
        let runtime_green_candidate = summary
            .pointer("/runtime_green_candidate")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let durable_writes = match self.persist_agent_browser_final_validation_result(&result) {
            Ok(writes) => writes,
            Err(error) => {
                self.report_action_error(
                    "Final validation result managed proof write failed",
                    error,
                    cx,
                );
                cx.notify();
                return;
            }
        };
        self.latest_agent_browser_final_validation_result = Some(result);
        let import_receipt = self.agent_browser_final_validation_result_import_receipt(
            &summary,
            &durable_writes,
            runtime_green_candidate,
        );
        self.latest_agent_browser_final_validation_result_import_receipt = Some(import_receipt);
        if runtime_green_candidate {
            self.show_toast(
                format!(
                    "Imported passing final validation result and wrote {} managed proof file(s)",
                    durable_writes.len()
                ),
                cx,
            );
        } else {
            self.show_toast(
                format!(
                    "Imported incomplete final validation result and wrote {} managed proof file(s)",
                    durable_writes.len()
                ),
                cx,
            );
        }
        cx.notify();
    }

