    fn agent_plugin_runtime_green_final_report_packet_snapshot(&self) -> Value {
        let report_gate = self.agent_plugin_runtime_green_report_gate_snapshot();
        let final_proof_guide =
            self.agent_plugin_runtime_green_final_proof_guide_from_report_gate(&report_gate);
        self.agent_plugin_runtime_green_final_report_packet_from_parts(
            &report_gate,
            &final_proof_guide,
        )
    }

    fn agent_plugin_runtime_green_final_report_packet_from_parts(
        &self,
        report_gate: &Value,
        final_proof_guide: &Value,
    ) -> Value {
        let observability = self.agent_browser_final_validation_observability();
        let import_receipt_summary =
            self.latest_agent_browser_final_validation_result_import_receipt_summary();
        let can_report = report_gate
            .get("can_report_runtime_green")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let report_gate_status = report_gate
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let report_gate_blocker = report_gate
            .get("blocker")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let next_report_action = report_gate
            .get("next_action")
            .and_then(Value::as_str)
            .unwrap_or("copy_agent_plugin_runtime_green_report_gate");
        let observability_runtime_green = observability
            .get("runtime_green_candidate")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let durable_runtime_green = observability
            .pointer("/durable_evidence/runtime_green_candidate")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let import_receipt_present = import_receipt_summary.is_some();
        let status = if can_report && import_receipt_present {
            "ready_to_report_runtime_green_with_import_receipt"
        } else if can_report {
            "ready_to_report_runtime_green_from_durable_evidence"
        } else {
            "blocked_by_report_gate"
        };
        let next_action = if can_report {
            "copy_agent_plugin_runtime_green_report_gate"
        } else {
            next_report_action
        };
        let blocker = if can_report {
            "none"
        } else {
            report_gate_blocker
        };
        let regression_watch = report_gate
            .get("regression_watch")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({}));

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_GREEN_FINAL_REPORT_PACKET_SCHEMA,
            "status": status,
            "generated_at_ms": Self::current_epoch_millis(),
            "may_report_runtime_green": can_report,
            "blocker": blocker,
            "next_action": next_action,
            "final_manual_command": "just run",
            "regression_watch": regression_watch,
            "report_gate": {
                "schema": AGENT_PLUGIN_RUNTIME_GREEN_REPORT_GATE_SCHEMA,
                "status": report_gate_status,
                "can_report_runtime_green": can_report,
                "blocker": report_gate_blocker,
                "label": report_gate.get("label").and_then(Value::as_str),
                "severity": report_gate.get("severity").and_then(Value::as_str),
                "next_action": next_report_action,
                "badge": report_gate.get("badge").cloned(),
                "copy_action": "copy_agent_plugin_runtime_green_report_gate",
                "send_action": "send_agent_plugin_runtime_green_report_gate_to_agent"
            },
            "final_result_import_receipt": {
                "schema": AGENT_BROWSER_FINAL_VALIDATION_RESULT_IMPORT_RECEIPT_SCHEMA,
                "present_in_session": import_receipt_present,
                "latest_summary": import_receipt_summary,
                "copy_action": "copy_agent_browser_final_validation_result_import_receipt",
                "send_action": "send_agent_browser_final_validation_result_import_receipt_to_agent",
                "import_action": "import_agent_browser_final_validation_result_from_clipboard"
            },
            "final_validation_observability": {
                "schema": AGENT_BROWSER_FINAL_VALIDATION_OBSERVABILITY_SCHEMA,
                "status": observability.get("status").and_then(Value::as_str),
                "runtime_green_candidate": observability_runtime_green,
                "durable_runtime_green_candidate": durable_runtime_green,
                "missing": observability.get("missing").cloned(),
                "recovery_actions": observability.get("recovery_actions").cloned()
            },
            "final_proof_guide": {
                "schema": AGENT_PLUGIN_RUNTIME_GREEN_FINAL_PROOF_GUIDE_SCHEMA,
                "status": final_proof_guide.get("status").and_then(Value::as_str),
                "blocker": final_proof_guide.get("blocker").and_then(Value::as_str),
                "next_action": final_proof_guide.get("next_action").and_then(Value::as_str),
                "copy_action": "copy_agent_plugin_runtime_green_final_proof_guide",
                "send_action": "send_agent_plugin_runtime_green_final_proof_guide_to_agent"
            },
            "required_evidence": [
                {
                    "id": "report_gate_allows_runtime_green",
                    "ready": can_report,
                    "source": "runtime_green_report_gate.can_report_runtime_green",
                    "required_for_final_status_claim": true
                },
                {
                    "id": "manual_final_validation_result",
                    "ready": observability_runtime_green || durable_runtime_green,
                    "source": "final_validation_observability.runtime_green_candidate",
                    "required_for_final_status_claim": true
                },
                {
                    "id": "post_import_receipt_handoff",
                    "ready": import_receipt_present,
                    "source": "final_validation_result_import_receipt.latest_summary",
                    "required_for_handoff_audit": true
                }
            ],
            "reporting_policy": {
                "may_report_runtime_green": can_report,
                "source_of_truth": "runtime_green_report_gate",
                "requires_final_manual_command": "just run",
                "requires_imported_final_result": true,
                "import_receipt_recommended_for_handoff": true,
                "requires_regression_watch_review_before_manual_claim": true
            },
            "copy_action": "copy_agent_plugin_runtime_green_final_report_packet",
            "send_action": "send_agent_plugin_runtime_green_final_report_packet_to_agent",
            "read_only": true,
            "writes_files": false,
            "runs_node": false,
            "launches_browser": false,
            "dispatches_input": false,
        })
    }

    fn agent_plugin_runtime_green_report_readiness_card_snapshot(&self) -> Value {
        let claim_readiness = self.agent_plugin_runtime_green_claim_readiness_snapshot();
        let report_gate =
            Self::agent_plugin_runtime_green_report_gate_from_readiness(&claim_readiness);
        let final_proof_guide =
            self.agent_plugin_runtime_green_final_proof_guide_from_report_gate(&report_gate);
        let final_report_packet = self.agent_plugin_runtime_green_final_report_packet_from_parts(
            &report_gate,
            &final_proof_guide,
        );
        let final_proof_audit = self.agent_browser_final_proof_audit();

        Self::agent_plugin_runtime_green_report_readiness_card_from_parts(
            &claim_readiness,
            &report_gate,
            &final_report_packet,
            &final_proof_audit,
        )
    }

    fn agent_plugin_runtime_green_report_readiness_card_from_parts(
        claim_readiness: &Value,
        report_gate: &Value,
        final_report_packet: &Value,
        final_proof_audit: &Value,
    ) -> Value {
        let may_report_runtime_green = final_report_packet
            .get("may_report_runtime_green")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let report_gate_can_report = report_gate
            .get("can_report_runtime_green")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let audit_status = final_proof_audit
            .pointer("/audit/status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let final_result_present = final_proof_audit
            .pointer("/latest/final_validation_result")
            .map(|result| !result.is_null())
            .unwrap_or(false);
        let final_result_runtime_green = final_proof_audit
            .pointer("/audit/runtime_green_candidate")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let status = if may_report_runtime_green && report_gate_can_report {
            "ready_to_report_runtime_green"
        } else if audit_status == "awaiting_final_runtime_result_import" {
            "final_runtime_result_import_required"
        } else if audit_status == "final_result_needs_evidence_or_blocker_fix" {
            "final_runtime_result_evidence_required"
        } else {
            "runtime_green_report_blocked"
        };
        let next_action = final_report_packet
            .get("next_action")
            .and_then(Value::as_str)
            .or_else(|| {
                final_proof_audit
                    .pointer("/audit/next_action")
                    .and_then(Value::as_str)
            })
            .or_else(|| report_gate.get("next_action").and_then(Value::as_str))
            .unwrap_or("copy_agent_plugin_runtime_green_report_gate");
        let blocker = final_report_packet
            .get("blocker")
            .and_then(Value::as_str)
            .or_else(|| report_gate.get("blocker").and_then(Value::as_str))
            .unwrap_or("unknown");
        let regression_watch = final_report_packet
            .get("regression_watch")
            .or_else(|| report_gate.get("regression_watch"))
            .unwrap_or(&Value::Null);

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_GREEN_REPORT_READINESS_CARD_SCHEMA,
            "status": status,
            "generated_at_ms": Self::current_epoch_millis(),
            "may_report_runtime_green": may_report_runtime_green,
            "blocker": blocker,
            "next_action": next_action,
            "final_manual_command": "just run",
            "claim_readiness": {
                "schema": AGENT_PLUGIN_RUNTIME_GREEN_CLAIM_READINESS_SCHEMA,
                "status": claim_readiness.get("status").and_then(Value::as_str),
                "can_report_runtime_green": claim_readiness
                    .get("can_report_runtime_green")
                    .and_then(Value::as_bool),
                "ready_lane_fraction": claim_readiness
                    .get("ready_lane_fraction")
                    .and_then(Value::as_str),
                "first_pending_lane_label": claim_readiness
                    .get("first_pending_lane_label")
                    .and_then(Value::as_str),
                "first_pending_lane_status": claim_readiness
                    .get("first_pending_lane_status")
                    .and_then(Value::as_str),
                "next_required_proof_id": claim_readiness
                    .get("next_required_proof_id")
                    .and_then(Value::as_str),
                "next_recommended_action": claim_readiness
                    .get("next_recommended_action")
                    .and_then(Value::as_str),
            },
            "report_gate": {
                "schema": AGENT_PLUGIN_RUNTIME_GREEN_REPORT_GATE_SCHEMA,
                "status": report_gate.get("status").and_then(Value::as_str),
                "can_report_runtime_green": report_gate_can_report,
                "blocker": report_gate.get("blocker").and_then(Value::as_str),
                "severity": report_gate.get("severity").and_then(Value::as_str),
                "badge": report_gate.get("badge").cloned(),
                "next_action": report_gate.get("next_action").and_then(Value::as_str),
            },
            "final_report_packet": {
                "schema": AGENT_PLUGIN_RUNTIME_GREEN_FINAL_REPORT_PACKET_SCHEMA,
                "status": final_report_packet.get("status").and_then(Value::as_str),
                "may_report_runtime_green": may_report_runtime_green,
                "blocker": final_report_packet.get("blocker").and_then(Value::as_str),
                "next_action": final_report_packet.get("next_action").and_then(Value::as_str),
                "import_receipt_present": final_report_packet
                    .pointer("/final_result_import_receipt/present_in_session")
                    .and_then(Value::as_bool),
            },
            "final_proof_audit": {
                "schema": AGENT_BROWSER_FINAL_PROOF_AUDIT_SCHEMA,
                "status": audit_status,
                "runtime_green_candidate": final_proof_audit
                    .pointer("/audit/runtime_green_candidate")
                    .and_then(Value::as_bool),
                "final_result_present": final_result_present,
                "final_result_runtime_green": final_result_runtime_green,
                "may_report_runtime_green": final_proof_audit
                    .pointer("/audit/may_report_runtime_green")
                    .and_then(Value::as_bool),
                "missing_required_check_count": final_proof_audit
                    .pointer("/audit/missing_required_checks")
                    .and_then(Value::as_array)
                    .map(Vec::len),
                "missing_required_evidence_count": final_proof_audit
                    .pointer("/audit/missing_required_evidence")
                    .and_then(Value::as_array)
                    .map(Vec::len),
                "required_check_blocker_count": final_proof_audit
                    .pointer("/audit/required_check_blocker_count")
                    .and_then(Value::as_u64),
                "has_overall_blocker": final_proof_audit
                    .pointer("/audit/has_overall_blocker")
                    .and_then(Value::as_bool),
                "next_action": final_proof_audit
                    .pointer("/audit/next_action")
                    .and_then(Value::as_str),
            },
            "regression_watch": {
                "schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_WATCH_ROLLUP_SCHEMA,
                "status": regression_watch.get("status").and_then(Value::as_str),
                "watched_plugin_count": regression_watch
                    .get("watched_plugin_count")
                    .and_then(Value::as_u64),
                "total_must_recheck_count": regression_watch
                    .get("total_must_recheck_count")
                    .and_then(Value::as_u64),
                "total_must_not_regress_count": regression_watch
                    .get("total_must_not_regress_count")
                    .and_then(Value::as_u64),
                "first_watch_status": regression_watch
                    .pointer("/first_watch/status")
                    .and_then(Value::as_str),
                "review_before_runtime_green_claim": true,
            },
            "copy_action": "copy_agent_plugin_runtime_green_report_readiness_card",
            "send_action": "send_agent_plugin_runtime_green_report_readiness_card_to_agent",
            "final_report_packet_copy_action": "copy_agent_plugin_runtime_green_final_report_packet",
            "final_report_packet_send_action": "send_agent_plugin_runtime_green_final_report_packet_to_agent",
            "report_gate_copy_action": "copy_agent_plugin_runtime_green_report_gate",
            "report_gate_send_action": "send_agent_plugin_runtime_green_report_gate_to_agent",
            "audit_copy_action": "copy_agent_browser_final_proof_audit",
            "audit_send_action": "send_agent_browser_final_proof_audit_to_agent",
            "read_only": true,
            "writes_files": false,
            "runs_node": false,
            "launches_browser": false,
            "dispatches_input": false,
        })
    }

    fn agent_plugin_runtime_green_next_required_proof(
        current_best_next: &Value,
        runtime_green_candidate: bool,
    ) -> Value {
        let lane_id = current_best_next
            .get("lane_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let lane_label = current_best_next
            .get("label")
            .and_then(Value::as_str)
            .unwrap_or(lane_id);
        let lane_status = current_best_next
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let primary_actions = current_best_next
            .get("primary_actions")
            .cloned()
            .unwrap_or_else(|| serde_json::json!([]));
        let recommended_action = current_best_next
            .pointer("/primary_actions/0")
            .and_then(Value::as_str)
            .unwrap_or("copy_agent_plugin_runtime_green_claim_gate");

        match lane_id {
            "browser_webpreview" => serde_json::json!({
                "lane_id": lane_id,
                "label": lane_label,
                "status": lane_status,
                "required_proof_id": "browser_final_validation_result_runtime_green",
                "required_proof_field": "agent_browser_final_validation_result.runtime_green_candidate",
                "recommended_action": recommended_action,
                "recommended_actions": primary_actions,
                "recommended_sequence": [
                    "copy_agent_browser_final_validation_bundle",
                    "copy_agent_browser_final_validation_result_template",
                    "run just run manually when ready for final runtime proof",
                    "import_agent_browser_final_validation_result_from_clipboard",
                    "copy_agent_browser_final_validation_result_import_receipt",
                    "copy_agent_plugin_runtime_green_claim_gate"
                ],
                "managed_proof_write": "only import_agent_browser_final_validation_result_from_clipboard writes managed final-proof JSON after explicit user action",
                "writes_files": false,
                "dispatches_input": false
            }),
            "managed_chrome" => serde_json::json!({
                "lane_id": lane_id,
                "label": lane_label,
                "status": lane_status,
                "required_proof_id": "managed_chrome_completed_execution_receipt",
                "required_proof_field": "managed_chrome_execution.latest_receipt.read.outcome == completed",
                "recommended_action": recommended_action,
                "recommended_actions": primary_actions,
                "recommended_sequence": [
                    "send_agent_plugin_bootstrap_readiness_to_agent",
                    "send_managed_chrome_execution_status_to_agent",
                    "inspect_agent_plugin_runtime_status with include_runtime_green_claim_gate=true"
                ],
                "managed_proof_write": "permissioned Agent tools may write managed receipts only under managed plugin roots",
                "writes_files": false,
                "dispatches_input": false
            }),
            "pc_use" => serde_json::json!({
                "lane_id": lane_id,
                "label": lane_label,
                "status": lane_status,
                "required_proof_id": "pc_use_ready_runner_receipt",
                "required_proof_field": "pc_use_status.status == has_ready_runner_receipt",
                "recommended_action": recommended_action,
                "recommended_actions": primary_actions,
                "recommended_sequence": [
                    "send_pc_use_status_to_agent",
                    "inspect_zed_pc_use_payload_queue",
                    "request_zed_pc_use_payload_run",
                    "inspect_zed_pc_use_runner_receipts"
                ],
                "managed_proof_write": "request_zed_pc_use_payload_run may write a managed future-executor receipt only after explicit authorization",
                "writes_files": false,
                "dispatches_input": false
            }),
            _ => serde_json::json!({
                "lane_id": lane_id,
                "label": lane_label,
                "status": lane_status,
                "required_proof_id": if runtime_green_candidate {
                    "final_manual_windows_runtime_proof"
                } else {
                    "runtime_green_claim_gate_recheck"
                },
                "required_proof_field": if runtime_green_candidate {
                    "manual final just run result imported into WebPreview"
                } else {
                    "runtime_green_claim_gate.status"
                },
                "recommended_action": recommended_action,
                "recommended_actions": primary_actions,
                "recommended_sequence": if runtime_green_candidate {
                    serde_json::json!([
                        "run just run manually",
                        "copy_agent_browser_final_validation_result_template",
                        "import_agent_browser_final_validation_result_from_clipboard",
                        "copy_agent_browser_final_validation_result_import_receipt",
                        "copy_agent_plugin_runtime_green_claim_gate"
                    ])
                } else {
                    serde_json::json!(["copy_agent_plugin_runtime_green_claim_gate"])
                },
                "managed_proof_write": "only explicit WebPreview import actions write managed proof JSON",
                "writes_files": false,
                "dispatches_input": false
            }),
        }
    }

    fn agent_plugin_runtime_green_final_operator_checklist(
        next_required_proof: &Value,
        runtime_green_candidate: bool,
    ) -> Value {
        let required_proof_id = next_required_proof
            .get("required_proof_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let recommended_action = next_required_proof
            .get("recommended_action")
            .and_then(Value::as_str)
            .unwrap_or("copy_agent_plugin_runtime_green_claim_gate");
        let recommended_sequence = next_required_proof
            .get("recommended_sequence")
            .cloned()
            .unwrap_or_else(|| serde_json::json!([]));
        let status = if runtime_green_candidate {
            "ready_for_final_windows_runtime_proof"
        } else {
            "blocked_by_required_proof"
        };

        serde_json::json!({
            "status": status,
            "can_run_final_manual_command": runtime_green_candidate,
            "final_manual_command": "just run",
            "first_required_proof_id": required_proof_id,
            "first_recommended_action": recommended_action,
            "recommended_sequence": recommended_sequence,
            "ordered_checks": [
                {
                    "id": "read_claim_gate",
                    "label": "Read the compact runtime-green claim gate.",
                    "status": "ready",
                    "action": "copy_agent_plugin_runtime_green_claim_gate",
                    "writes_files": false,
                    "dispatches_input": false
                },
                {
                    "id": "resolve_first_required_proof",
                    "label": "Resolve the first missing runtime proof before the final manual pass.",
                    "status": if runtime_green_candidate { "ready" } else { "required" },
                    "required_proof_id": required_proof_id,
                    "recommended_action": recommended_action,
                    "writes_files": next_required_proof
                        .get("writes_files")
                        .and_then(Value::as_bool)
                        .unwrap_or(false),
                    "dispatches_input": next_required_proof
                        .get("dispatches_input")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                },
                {
                    "id": "run_final_windows_runtime_proof",
                    "label": "Run the final manual Windows runtime proof only after required proof is available.",
                    "status": if runtime_green_candidate { "required" } else { "blocked" },
                    "command": "just run",
                    "writes_files": false,
                    "dispatches_input": false
                },
                {
                    "id": "import_final_result",
                    "label": "Import the filled final validation result after the manual proof.",
                    "status": if runtime_green_candidate { "pending_manual_result" } else { "blocked" },
                    "action": "import_agent_browser_final_validation_result_from_clipboard",
                    "managed_proof_write": "writes managed final-proof JSON only after explicit WebPreview import",
                    "dispatches_input": false
                },
                {
                    "id": "copy_import_receipt",
                    "label": "Copy the final validation result import receipt.",
                    "status": "required_after_import",
                    "action": "copy_agent_browser_final_validation_result_import_receipt",
                    "writes_files": false,
                    "dispatches_input": false
                },
                {
                    "id": "recheck_claim_gate",
                    "label": "Re-read the claim gate and proof path before reporting runtime-green.",
                    "status": "required_after_changes",
                    "action": "copy_agent_plugin_runtime_green_claim_gate",
                    "writes_files": false,
                    "dispatches_input": false
                }
            ],
            "reporting_policy": {
                "may_report_runtime_green": false,
                "reason": "The code path can only prepare or summarize evidence; a final manual Windows runtime proof and imported result are still required before a runtime-green report.",
                "requires_imported_final_result": true
            },
            "read_only": true
        })
    }

    fn agent_plugin_runtime_green_operator_handoff(&self, window: &Window) -> Value {
        let root_mode = self.runtime_green_root_mode();
        let browser_final_observability = self.agent_browser_final_validation_observability();
        let browser_result_summary = self.latest_agent_browser_final_validation_result_summary();
        let bootstrap_readiness = self.agent_plugin_bootstrap_readiness();
        let managed_chrome_execution = self.managed_chrome_execution_status();
        let pc_use_status = self.pc_use_status();

        let browser_ready = browser_result_summary
            .as_ref()
            .and_then(|summary| summary.get("runtime_green_candidate"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let browser_result_present = browser_result_summary.is_some();
        let bootstrap_ready = bootstrap_readiness.get("status").and_then(Value::as_str)
            == Some("ready_for_managed_chrome_executor");
        let managed_chrome_receipt_completed = managed_chrome_execution
            .pointer("/latest_receipt/read/outcome")
            .and_then(Value::as_str)
            == Some("completed");
        let managed_chrome_ready = bootstrap_ready && managed_chrome_receipt_completed;
        let pc_use_ready =
            pc_use_status.get("status").and_then(Value::as_str) == Some("has_ready_runner_receipt");

        let lanes = vec![
            serde_json::json!({
                "lane_id": "browser_webpreview",
                "label": "Browser/WebPreview",
                "ready": browser_ready,
                "status": if browser_ready {
                    "ready"
                } else if browser_result_present {
                    "manual_result_not_runtime_green"
                } else {
                    "missing_final_validation_result"
                },
                "checks": {
                    "final_validation_result_runtime_green": browser_ready,
                    "final_validation_observability_status": browser_final_observability.get("status").and_then(Value::as_str),
                    "latest_result_summary": browser_result_summary,
                },
                "operator_actions": {
                    "copy_final_proof_state": "copy_agent_browser_final_validation_observability",
                    "send_final_proof_state": "send_agent_browser_final_validation_observability_to_agent",
                    "copy_final_validation_bundle": "copy_agent_browser_final_validation_bundle",
                    "send_final_validation_bundle": "send_agent_browser_final_validation_bundle_to_agent",
                    "import_final_result": "import_agent_browser_final_validation_result_from_clipboard",
                    "copy_final_result_import_receipt": "copy_agent_browser_final_validation_result_import_receipt",
                    "send_final_result_import_receipt": "send_agent_browser_final_validation_result_import_receipt_to_agent"
                }
            }),
            serde_json::json!({
                "lane_id": "managed_chrome",
                "label": "Managed Chrome/Playwright",
                "ready": managed_chrome_ready,
                "status": if managed_chrome_ready {
                    "ready"
                } else if !bootstrap_ready {
                    "bootstrap_or_assets_not_ready"
                } else {
                    managed_chrome_execution.get("status").and_then(Value::as_str).unwrap_or("missing_completed_execution_receipt")
                },
                "checks": {
                    "bootstrap_ready": bootstrap_ready,
                    "execution_receipt_completed": managed_chrome_receipt_completed,
                    "bootstrap_status": bootstrap_readiness.get("status").and_then(Value::as_str),
                    "execution_status": managed_chrome_execution.get("status").and_then(Value::as_str),
                    "latest_execution_outcome": managed_chrome_execution.pointer("/latest_receipt/read/outcome").and_then(Value::as_str),
                },
                "operator_actions": {
                    "copy_bootstrap_readiness": "copy_agent_plugin_bootstrap_readiness",
                    "send_bootstrap_readiness": "send_agent_plugin_bootstrap_readiness_to_agent",
                    "copy_execution_status": "copy_managed_chrome_execution_status",
                    "send_execution_status": "send_managed_chrome_execution_status_to_agent"
                }
            }),
            serde_json::json!({
                "lane_id": "pc_use",
                "label": "Zed PC-use",
                "ready": pc_use_ready,
                "status": if pc_use_ready {
                    "ready"
                } else {
                    pc_use_status.get("status").and_then(Value::as_str).unwrap_or("empty")
                },
                "checks": {
                    "runner_receipt_ready": pc_use_ready,
                    "latest_outcome": pc_use_status.get("latest_outcome").and_then(Value::as_str),
                },
                "operator_actions": {
                    "copy_pc_use_status": "copy_pc_use_status",
                    "send_pc_use_status": "send_pc_use_status_to_agent"
                }
            }),
        ];
        let ready_lane_count = lanes
            .iter()
            .filter(|lane| lane.get("ready").and_then(Value::as_bool).unwrap_or(false))
            .count();
        let runtime_green_candidate = browser_ready && managed_chrome_ready && pc_use_ready;
        let current_best_next = lanes
            .iter()
            .find(|lane| {
                lane.get("ready")
                    .and_then(Value::as_bool)
                    .map(|ready| !ready)
                    .unwrap_or(true)
            })
            .cloned()
            .unwrap_or_else(|| {
                serde_json::json!({
                    "lane_id": "final_runtime_validation",
                    "label": "Final Windows runtime validation",
                    "ready": false,
                    "status": "manual_required",
                    "operator_actions": {
                        "inspect_runtime_status": "inspect_agent_plugin_runtime_status",
                        "manual_command": "just run"
                    }
                })
            });

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_GREEN_OPERATOR_HANDOFF_SCHEMA,
            "generated_at_ms": Self::current_epoch_millis(),
            "source": "web_preview",
            "status": if runtime_green_candidate {
                "runtime_green_candidate"
            } else {
                "operator_action_required"
            },
            "runtime_green_candidate": runtime_green_candidate,
            "root_mode": root_mode,
            "session": self.browser_session_snapshot(window),
            "summary": {
                "lane_count": lanes.len(),
                "ready_lane_count": ready_lane_count,
                "current_best_next_lane": current_best_next.get("lane_id").and_then(Value::as_str),
            },
            "current_best_next": current_best_next,
            "lanes": lanes,
            "webpreview_evidence": {
                "final_validation_observability": browser_final_observability,
                "plugin_bootstrap_readiness": bootstrap_readiness,
                "managed_chrome_execution_status": managed_chrome_execution,
                "pc_use_status": pc_use_status,
            },
            "agent_runtime_status_tool": {
                "tool_name": "inspect_agent_plugin_runtime_status",
                "schema": "zed.agent_plugins.runtime_status.v1",
                "scorecard_schema": AGENT_PLUGIN_RUNTIME_GREEN_SCORECARD_SCHEMA,
                "operator_handoff_schema": AGENT_PLUGIN_RUNTIME_GREEN_OPERATOR_HANDOFF_SCHEMA,
                "proof_path_schema": AGENT_PLUGIN_RUNTIME_GREEN_PROOF_PATH_SCHEMA,
                "payload": runtime_green_status_payload(root_mode)
            },
            "copy_action": "copy_agent_plugin_runtime_green_handoff",
            "send_action": "send_agent_plugin_runtime_green_handoff_to_agent",
            "safety": {
                "read_only": true,
                "writes_files": false,
                "runs_node": false,
                "launches_browser": false,
                "dispatches_input": false,
                "touches_real_browser_profiles": false,
                "permissioned_steps_require_user_visible_authorization": true
            }
        })
    }

    fn agent_plugin_runtime_green_operator_handoff_summary(handoff: &Value) -> Value {
        serde_json::json!({
            "schema": handoff.get("schema").and_then(Value::as_str),
            "status": handoff.get("status").and_then(Value::as_str),
            "runtime_green_candidate": handoff.get("runtime_green_candidate").and_then(Value::as_bool),
            "root_mode": handoff.get("root_mode").and_then(Value::as_str),
            "ready_lane_count": handoff.pointer("/summary/ready_lane_count").and_then(Value::as_u64),
            "lane_count": handoff.pointer("/summary/lane_count").and_then(Value::as_u64),
            "current_best_next_lane": handoff.pointer("/summary/current_best_next_lane").and_then(Value::as_str),
        })
    }

    fn agent_plugin_runtime_observability_digest(&self, window: &Window) -> Value {
        let handoff = self.agent_plugin_runtime_green_operator_handoff(window);
        self.agent_plugin_runtime_observability_digest_from_handoff(&handoff)
    }

    fn agent_plugin_runtime_observability_digest_from_handoff(&self, handoff: &Value) -> Value {
        let lanes = handoff
            .get("lanes")
            .and_then(Value::as_array)
            .map(|lanes| {
                lanes
                    .iter()
                    .map(|lane| {
                        serde_json::json!({
                            "lane_id": lane.get("lane_id").and_then(Value::as_str),
                            "status": lane.get("status").and_then(Value::as_str),
                            "ready": lane.get("ready").and_then(Value::as_bool).unwrap_or(false),
                            "operator_actions": lane
                                .get("operator_actions")
                                .cloned()
                                .unwrap_or_else(|| serde_json::json!({})),
                        })
                    })
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let pending_lane_count = lanes
            .iter()
            .filter(|lane| !lane.get("ready").and_then(Value::as_bool).unwrap_or(false))
            .count();
        let plugin_matrix =
            Self::agent_plugin_runtime_observability_plugin_matrix_from_handoff(&lanes, handoff);
        let runtime_green_candidate = handoff
            .get("runtime_green_candidate")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let status = if runtime_green_candidate {
            "runtime_green_candidate"
        } else if pending_lane_count == 0 {
            "ready_for_final_runtime_validation"
        } else {
            "operator_action_required"
        };

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_DIGEST_SCHEMA,
            "generated_at_ms": Self::current_epoch_millis(),
            "source": "web_preview",
            "status": status,
            "runtime_green_candidate": runtime_green_candidate,
            "root_mode": handoff.get("root_mode").and_then(Value::as_str),
            "session": handoff
                .get("session")
                .cloned()
                .unwrap_or_else(|| serde_json::json!({})),
            "summary": {
                "lane_count": handoff.pointer("/summary/lane_count").and_then(Value::as_u64),
                "ready_lane_count": handoff.pointer("/summary/ready_lane_count").and_then(Value::as_u64),
                "pending_lane_count": pending_lane_count,
                "current_best_next_lane": handoff.pointer("/summary/current_best_next_lane").and_then(Value::as_str),
            },
            "lane_statuses": lanes,
            "plugin_matrix": plugin_matrix,
            "proof_focus": {
                "browser_final_validation": {
                    "status": handoff.pointer("/webpreview_evidence/final_validation_observability/status").and_then(Value::as_str),
                    "runtime_green_candidate": handoff.pointer("/webpreview_evidence/final_validation_observability/runtime_green_candidate").and_then(Value::as_bool),
                    "missing": handoff
                        .pointer("/webpreview_evidence/final_validation_observability/missing")
                        .cloned()
                        .unwrap_or_else(|| serde_json::json!([])),
                    "recovery_actions": handoff
                        .pointer("/webpreview_evidence/final_validation_observability/recovery_actions")
                        .cloned()
                        .unwrap_or_else(|| serde_json::json!({})),
                },
                "managed_chrome": {
                    "bootstrap_status": handoff.pointer("/webpreview_evidence/plugin_bootstrap_readiness/status").and_then(Value::as_str),
                    "execution_status": handoff.pointer("/webpreview_evidence/managed_chrome_execution_status/status").and_then(Value::as_str),
                    "latest_execution_outcome": handoff.pointer("/webpreview_evidence/managed_chrome_execution_status/latest_receipt/read/outcome").and_then(Value::as_str),
                },
                "pc_use": {
                    "status": handoff.pointer("/webpreview_evidence/pc_use_status/status").and_then(Value::as_str),
                    "latest_outcome": handoff.pointer("/webpreview_evidence/pc_use_status/latest_outcome").and_then(Value::as_str),
                }
            },
            "current_best_next": handoff
                .get("current_best_next")
                .cloned()
                .unwrap_or_else(|| serde_json::json!({})),
            "agent_runtime_status_tool": {
                "tool_name": "inspect_agent_plugin_runtime_status",
                "schema": "zed.agent_plugins.runtime_status.v1",
                "observability_digest_schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_DIGEST_SCHEMA,
                "observability_plugin_matrix_schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_MATRIX_SCHEMA,
                "observability_regression_watch_rollup_schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_WATCH_ROLLUP_SCHEMA,
                "proof_path_schema": AGENT_PLUGIN_RUNTIME_GREEN_PROOF_PATH_SCHEMA,
                "payload": runtime_green_status_payload(
                    handoff
                        .get("root_mode")
                        .and_then(Value::as_str)
                        .unwrap_or("workspace"),
                )
            },
            "copy_action": "copy_agent_plugin_runtime_observability_digest",
            "send_action": "send_agent_plugin_runtime_observability_digest_to_agent",
            "expanded_operator_handoff": {
                "schema": AGENT_PLUGIN_RUNTIME_GREEN_OPERATOR_HANDOFF_SCHEMA,
                "copy_action": "copy_agent_plugin_runtime_green_handoff",
                "send_action": "send_agent_plugin_runtime_green_handoff_to_agent"
            },
            "safety": {
                "read_only": true,
                "writes_files": false,
                "runs_node": false,
                "launches_browser": false,
                "dispatches_input": false,
                "touches_real_browser_profiles": false
            }
        })
    }

    fn agent_plugin_runtime_observability_digest_summary(digest: &Value) -> Value {
        serde_json::json!({
            "schema": digest.get("schema").and_then(Value::as_str),
            "status": digest.get("status").and_then(Value::as_str),
            "runtime_green_candidate": digest.get("runtime_green_candidate").and_then(Value::as_bool),
            "root_mode": digest.get("root_mode").and_then(Value::as_str),
            "ready_lane_count": digest.pointer("/summary/ready_lane_count").and_then(Value::as_u64),
            "lane_count": digest.pointer("/summary/lane_count").and_then(Value::as_u64),
            "pending_lane_count": digest.pointer("/summary/pending_lane_count").and_then(Value::as_u64),
            "plugin_matrix_status": digest.pointer("/plugin_matrix/status").and_then(Value::as_str),
            "ready_plugin_count": digest.pointer("/plugin_matrix/ready_plugin_count").and_then(Value::as_u64),
            "pending_plugin_count": digest.pointer("/plugin_matrix/pending_plugin_count").and_then(Value::as_u64),
            "first_priority_action": digest.pointer("/plugin_matrix/first_priority/action").and_then(Value::as_str),
            "first_priority_status": digest.pointer("/plugin_matrix/first_priority/status").and_then(Value::as_str),
            "regression_watch_status": digest.pointer("/plugin_matrix/regression_watch_rollup/status").and_then(Value::as_str),
            "regression_watch_lane_count": digest.pointer("/plugin_matrix/regression_watch_rollup/watched_plugin_count").and_then(Value::as_u64),
            "first_regression_watch_status": digest.pointer("/plugin_matrix/regression_watch_rollup/first_watch/status").and_then(Value::as_str),
            "current_best_next_lane": digest.pointer("/summary/current_best_next_lane").and_then(Value::as_str),
        })
    }

    fn agent_plugin_runtime_observability_plugin_matrix_from_handoff(
        lanes: &[Value],
        handoff: &Value,
    ) -> Value {
        let rows = lanes
            .iter()
            .map(|lane| {
                Self::agent_plugin_runtime_observability_plugin_row_from_handoff(lane, handoff)
            })
            .collect::<Vec<_>>();
        let plugin_count = rows.len();
        let first_priority = rows
            .iter()
            .find(|row| !row.get("ready").and_then(Value::as_bool).unwrap_or(false))
            .and_then(|row| row.get("next_action"))
            .cloned();
        let ready_plugin_count = rows
            .iter()
            .filter(|row| row.get("ready").and_then(Value::as_bool).unwrap_or(false))
            .count();
        let pending_plugin_count = plugin_count.saturating_sub(ready_plugin_count);
        let regression_watch_rollup =
            Self::agent_plugin_runtime_observability_plugin_regression_watch_rollup(&rows);
        let status = if plugin_count == 0 {
            "empty"
        } else if pending_plugin_count == 0 {
            "all_plugins_have_required_runtime_evidence"
        } else {
            "plugin_runtime_evidence_pending"
        };

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_MATRIX_SCHEMA,
            "status": status,
            "plugin_count": plugin_count,
            "ready_plugin_count": ready_plugin_count,
            "pending_plugin_count": pending_plugin_count,
            "first_priority": first_priority,
            "regression_watch_rollup": regression_watch_rollup,
            "rows": rows,
            "reads_from": [
                "runtime_green_operator_handoff.lanes",
                "runtime_green_operator_handoff.webpreview_evidence.final_validation_observability",
                "runtime_green_operator_handoff.webpreview_evidence.managed_chrome_execution_status",
                "runtime_green_operator_handoff.webpreview_evidence.pc_use_status",
                "runtime_observability_plugin_regression_watch",
                "runtime_observability_plugin_regression_watch_rollup"
            ],
            "safety": {
                "matrix_is_read_only": true,
                "writes_files": false,
                "runs_node": false,
                "launches_browser": false,
                "dispatches_input": false,
                "touches_real_browser_profiles": false,
            }
        })
    }

    fn agent_plugin_runtime_observability_plugin_regression_watch_rollup(rows: &[Value]) -> Value {
        let watch_rows = rows
            .iter()
            .filter_map(|row| {
                let watch = row.get("regression_watch")?;
                let status = watch
                    .get("status")
                    .and_then(Value::as_str)
                    .unwrap_or("unknown_plugin_lane");
                if status == "unknown_plugin_lane" {
                    return None;
                }

                Some(serde_json::json!({
                    "lane_id": row.get("lane_id").and_then(Value::as_str).unwrap_or("unknown"),
                    "plugin_id": row.get("plugin_id").and_then(Value::as_str).unwrap_or("unknown"),
                    "ready": row.get("ready").and_then(Value::as_bool).unwrap_or(false),
                    "status": status,
                    "focus": watch.get("focus").cloned().unwrap_or(Value::Null),
                    "first_must_recheck": watch
                        .get("must_recheck")
                        .and_then(Value::as_array)
                        .and_then(|items| items.first())
                        .cloned()
                        .unwrap_or(Value::Null),
                    "first_must_not_regress": watch
                        .get("must_not_regress")
                        .and_then(Value::as_array)
                        .and_then(|items| items.first())
                        .cloned()
                        .unwrap_or(Value::Null),
                    "proof_source_count": watch
                        .get("proof_sources")
                        .and_then(Value::as_array)
                        .map(|items| items.len())
                        .unwrap_or(0),
                    "after_action_validation": watch
                        .get("after_action_validation")
                        .cloned()
                        .unwrap_or(Value::Null),
                }))
            })
            .collect::<Vec<_>>();
        let total_must_recheck_count = rows
            .iter()
            .map(|row| {
                row.pointer("/regression_watch/must_recheck")
                    .and_then(Value::as_array)
                    .map(|items| items.len())
                    .unwrap_or(0)
            })
            .sum::<usize>();
        let total_must_not_regress_count = rows
            .iter()
            .map(|row| {
                row.pointer("/regression_watch/must_not_regress")
                    .and_then(Value::as_array)
                    .map(|items| items.len())
                    .unwrap_or(0)
            })
            .sum::<usize>();
        let total_proof_source_count = rows
            .iter()
            .map(|row| {
                row.pointer("/regression_watch/proof_sources")
                    .and_then(Value::as_array)
                    .map(|items| items.len())
                    .unwrap_or(0)
            })
            .sum::<usize>();

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_WATCH_ROLLUP_SCHEMA,
            "status": if watch_rows.is_empty() {
                "no_regression_watch_lanes"
            } else {
                "regression_watch_required"
            },
            "watched_plugin_count": watch_rows.len(),
            "total_must_recheck_count": total_must_recheck_count,
            "total_must_not_regress_count": total_must_not_regress_count,
            "total_proof_source_count": total_proof_source_count,
            "first_watch": watch_rows.first().cloned(),
            "watch_rows": watch_rows,
            "safety": {
                "rollup_is_read_only": true,
                "writes_files": false,
                "runs_node": false,
                "launches_browser": false,
                "dispatches_input": false,
                "touches_real_browser_profiles": false,
            }
        })
    }

    fn agent_plugin_runtime_observability_plugin_row_from_handoff(
        lane: &Value,
        handoff: &Value,
    ) -> Value {
        let lane_id = lane
            .get("lane_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let ready = lane.get("ready").and_then(Value::as_bool).unwrap_or(false);
        let freshness = Self::agent_plugin_runtime_observability_plugin_freshness_from_handoff(
            lane_id, handoff,
        );
        let next_action = Self::agent_plugin_runtime_observability_plugin_next_action_from_handoff(
            lane_id, ready, lane, &freshness,
        );

        serde_json::json!({
            "lane_id": lane_id,
            "plugin_id": Self::agent_plugin_runtime_observability_plugin_id(lane_id),
            "status": lane.get("status").and_then(Value::as_str),
            "ready": ready,
            "currently_selected_by_handoff": handoff
                .pointer("/current_best_next/lane_id")
                .and_then(Value::as_str)
                .is_some_and(|current_lane_id| current_lane_id == lane_id),
            "code_score": Self::agent_plugin_runtime_observability_plugin_code_score(lane_id),
            "proof": Self::agent_plugin_runtime_observability_plugin_proof_from_handoff(lane_id, handoff),
            "evidence_freshness": freshness,
            "next_action": next_action,
            "regression_watch": Self::agent_plugin_runtime_observability_plugin_regression_watch(lane_id),
            "handoff": lane
                .get("operator_actions")
                .cloned()
                .unwrap_or_else(|| serde_json::json!({})),
            "watch_surfaces": Self::agent_plugin_runtime_observability_plugin_watch_surfaces(lane_id),
            "safety": {
                "read_only_summary": true,
                "writes_files": false,
                "runs_node": false,
                "launches_browser": false,
                "dispatches_input": false,
                "touches_real_browser_profiles": false,
            }
        })
    }

    fn agent_plugin_runtime_observability_plugin_freshness_from_handoff(
        lane_id: &str,
        handoff: &Value,
    ) -> Value {
        match lane_id {
            "browser_webpreview" => {
                let runtime_green_candidate = handoff
                    .pointer("/webpreview_evidence/final_validation_observability/runtime_green_candidate")
                    .and_then(Value::as_bool)
                    .unwrap_or(false);
                let missing = handoff
                    .pointer("/webpreview_evidence/final_validation_observability/missing")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!([]));

                serde_json::json!({
                    "status": if runtime_green_candidate {
                        "session_evidence_current"
                    } else {
                        "manual_result_pending"
                    },
                    "source": "webpreview_evidence.final_validation_observability",
                    "missing": missing,
                    "does_not_probe_files": true,
                    "read_only": true,
                })
            }
            "managed_chrome" => {
                let bootstrap_ready = handoff
                    .pointer("/webpreview_evidence/plugin_bootstrap_readiness/status")
                    .and_then(Value::as_str)
                    == Some("ready_for_managed_chrome_executor");
                let execution_completed = handoff
                    .pointer("/webpreview_evidence/managed_chrome_execution_status/latest_receipt/read/outcome")
                    .and_then(Value::as_str)
                    == Some("completed");
                let status = if bootstrap_ready && execution_completed {
                    "session_evidence_current"
                } else if !bootstrap_ready {
                    "bootstrap_or_assets_pending"
                } else {
                    "execution_receipt_pending"
                };

                serde_json::json!({
                    "status": status,
                    "source": "webpreview_evidence.managed_chrome_execution_status",
                    "bootstrap_ready": bootstrap_ready,
                    "execution_receipt_completed": execution_completed,
                    "does_not_probe_files": true,
                    "read_only": true,
                })
            }
            "pc_use" => {
                let runner_receipt_ready = handoff
                    .pointer(
                        "/webpreview_evidence/pc_use_status/proof_summary/runner_receipt_ready",
                    )
                    .and_then(Value::as_bool)
                    .unwrap_or(false);
                let status = if runner_receipt_ready {
                    "session_evidence_current"
                } else {
                    "runner_receipt_pending"
                };

                serde_json::json!({
                    "status": status,
                    "source": "webpreview_evidence.pc_use_status",
                    "runner_receipt_ready": runner_receipt_ready,
                    "does_not_probe_files": true,
                    "read_only": true,
                })
            }
            _ => serde_json::json!({
                "status": "unknown_plugin_lane",
                "source": Value::Null,
                "does_not_probe_files": true,
                "read_only": true,
            }),
        }
    }

    fn agent_plugin_runtime_observability_plugin_next_action_from_handoff(
        lane_id: &str,
        ready: bool,
        lane: &Value,
        freshness: &Value,
    ) -> Value {
        let freshness_status = freshness
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let action = if ready {
            None
        } else {
            Self::agent_plugin_runtime_observability_plugin_default_next_action_from_handoff(
                lane_id,
                freshness_status,
            )
        };

        serde_json::json!({
            "status": if ready { "no_action_required" } else { freshness_status },
            "action": action,
            "source": "runtime_green_operator_handoff.webpreview_evidence",
            "lane_id": lane_id,
            "available_handoff_actions": lane
                .get("operator_actions")
                .cloned()
                .unwrap_or_else(|| serde_json::json!({})),
            "dispatches_input": false,
            "writes_files": false,
        })
    }

    fn agent_plugin_runtime_observability_plugin_default_next_action_from_handoff(
        lane_id: &str,
        freshness_status: &str,
    ) -> Option<&'static str> {
        match lane_id {
            "browser_webpreview" if freshness_status == "manual_result_pending" => {
                Some("copy_agent_browser_final_validation_bundle")
            }
            "browser_webpreview" => Some("copy_agent_browser_final_validation_observability"),
            "managed_chrome" if freshness_status == "bootstrap_or_assets_pending" => {
                Some("copy_agent_plugin_bootstrap_readiness")
            }
            "managed_chrome" => Some("copy_managed_chrome_execution_status"),
            "pc_use" => Some("copy_pc_use_status"),
            _ => None,
        }
    }

    fn agent_plugin_runtime_observability_plugin_regression_watch(lane_id: &str) -> Value {
        match lane_id {
            "browser_webpreview" => serde_json::json!({
                "status": "manual_runtime_watch_required",
                "focus": "Protect editor typing, caret position, WebPreview focus, and Browser executor receipt discipline.",
                "must_recheck": [
                    "Editor typing remains responsive before and after WebPreview Browser actions.",
                    "WebPreview focus returns to the expected surface after navigation, reload, tab switch, and URL edit.",
                    "Native click, type, key, scroll, history, and cache receipts remain fresh before any final runtime-green claim.",
                    "Final validation result import keeps durable evidence non-empty for every required manual check."
                ],
                "must_not_regress": [
                    "No browser action should route keyboard input to the editor or stale WebPreview item unexpectedly.",
                    "No read-only handoff should dispatch click, type, key, scroll, screenshot, or process-launch behavior.",
                    "No runtime-green report should be possible without the imported final validation result."
                ],
                "proof_sources": [
                    "agent_browser_executor_validation_progress",
                    "agent_browser_native_dispatch_receipt_matrix",
                    "agent_browser_final_validation_result_import_receipt",
                    "runtime_green_claim_gate"
                ],
                "after_action_validation": "Refresh the runtime observability digest, then copy the final proof audit before reporting status.",
                "read_only": true,
            }),
            "managed_chrome" => serde_json::json!({
                "status": "managed_profile_watch_required",
                "focus": "Keep managed Chrome/Playwright proof isolated to managed roots and safe read-only action receipts.",
                "must_recheck": [
                    "Managed roots stay under workspace or Zed-data plugin directories.",
                    "Real Chrome, Edge, and Firefox profiles are not read or written.",
                    "Adapter receipts still show only allowlisted safe actions: open_url, screenshot, inspect_element, dom_snapshot, runtime_events, set_viewport, or wait_for_selector.",
                    "Click, type, key, and scroll remain blocked in the managed Chrome adapter."
                ],
                "must_not_regress": [
                    "No Playwright execution should launch against a real user profile.",
                    "No managed Chrome receipt should hide failed requests, timeout status, or action outcome.",
                    "No catalog should advertise blocked input actions as executable."
                ],
                "proof_sources": [
                    "agent-plugin-asset-provisioning.json",
                    "managed_chrome_runner_receipt",
                    "managed_chrome_execution_receipt",
                    "managed_chrome_execution_status"
                ],
                "after_action_validation": "Inspect managed Chrome executions and re-read runtime status before advancing the runtime-green claim gate.",
                "read_only": true,
            }),
            "pc_use" => serde_json::json!({
                "status": "future_executor_watch_required",
                "focus": "Keep PC-use proof auditable while OS-wide control, screenshots, focus changes, and input dispatch stay disabled.",
                "must_recheck": [
                    "Every future input-ready payload references a matching UI snapshot target id and snapshot receipt id.",
                    "Runner receipts stay inspectable before any future executor exists.",
                    "Context, target manifest, and UI snapshot tools remain read-only.",
                    "PC-use status keeps explicit no-screenshot, no-focus, no-input, no-process, and no-OS-control flags."
                ],
                "must_not_regress": [
                    "No PC-use path should take screenshots, focus Zed, click, type, launch processes, or control the OS.",
                    "No guessed target id should pass as input-ready without a matching snapshot receipt.",
                    "No future-executor receipt should be treated as real execution proof."
                ],
                "proof_sources": [
                    "inspect_zed_window_context",
                    "inspect_zed_pc_use_targets",
                    "inspect_zed_pc_use_ui_snapshot",
                    "inspect_zed_pc_use_runner_receipts"
                ],
                "after_action_validation": "Re-read PC-use proof summary and runtime claim gate before reporting PC-use readiness.",
                "read_only": true,
            }),
            _ => serde_json::json!({
                "status": "unknown_plugin_lane",
                "focus": Value::Null,
                "must_recheck": [],
                "must_not_regress": [],
                "proof_sources": [],
                "after_action_validation": Value::Null,
                "read_only": true,
            }),
        }
    }

    fn agent_plugin_runtime_observability_plugin_proof_from_handoff(
        lane_id: &str,
        handoff: &Value,
    ) -> Value {
        match lane_id {
            "browser_webpreview" => serde_json::json!({
                "status": handoff
                    .pointer("/webpreview_evidence/final_validation_observability/status")
                    .and_then(Value::as_str)
                    .unwrap_or("missing_result"),
                "required_field": "webpreview_evidence.final_validation_observability.runtime_green_candidate",
                "runtime_green_candidate": handoff
                    .pointer("/webpreview_evidence/final_validation_observability/runtime_green_candidate")
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
                "missing": handoff
                    .pointer("/webpreview_evidence/final_validation_observability/missing")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!([])),
                "recovery_actions": handoff
                    .pointer("/webpreview_evidence/final_validation_observability/recovery_actions")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!({})),
            }),
            "managed_chrome" => serde_json::json!({
                "status": handoff
                    .pointer("/webpreview_evidence/managed_chrome_execution_status/status")
                    .and_then(Value::as_str)
                    .unwrap_or("missing_execution_receipt"),
                "required_field": "webpreview_evidence.managed_chrome_execution_status.latest_receipt.read.outcome == completed",
                "latest_execution_outcome": handoff
                    .pointer("/webpreview_evidence/managed_chrome_execution_status/latest_receipt/read/outcome")
                    .and_then(Value::as_str),
                "bootstrap_status": handoff
                    .pointer("/webpreview_evidence/plugin_bootstrap_readiness/status")
                    .and_then(Value::as_str),
                "execution_status": handoff
                    .pointer("/webpreview_evidence/managed_chrome_execution_status/status")
                    .and_then(Value::as_str),
            }),
            "pc_use" => serde_json::json!({
                "status": handoff
                    .pointer("/webpreview_evidence/pc_use_status/proof_summary/status")
                    .or_else(|| handoff.pointer("/webpreview_evidence/pc_use_status/status"))
                    .and_then(Value::as_str)
                    .unwrap_or("payload_missing"),
                "required_field": "webpreview_evidence.pc_use_status.proof_summary.runner_receipt_ready == true",
                "latest_outcome": handoff
                    .pointer("/webpreview_evidence/pc_use_status/latest_outcome")
                    .and_then(Value::as_str),
                "runner_receipt_ready": handoff
                    .pointer("/webpreview_evidence/pc_use_status/proof_summary/runner_receipt_ready")
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
                "proof_summary": handoff
                    .pointer("/webpreview_evidence/pc_use_status/proof_summary")
                    .cloned(),
            }),
            _ => serde_json::json!({
                "status": "unknown_plugin_lane",
                "required_field": Value::Null,
            }),
        }
    }

    fn agent_plugin_runtime_observability_plugin_id(lane_id: &str) -> &'static str {
        match lane_id {
            "browser_webpreview" => "zed.browser",
            "managed_chrome" => "zed.chrome",
            "pc_use" => "zed.pc_use",
            _ => "unknown",
        }
    }

    fn agent_plugin_runtime_observability_plugin_code_score(lane_id: &str) -> u64 {
        match lane_id {
            "browser_webpreview" => 99,
            "managed_chrome" => 94,
            "pc_use" => 91,
            _ => 0,
        }
    }

    fn agent_plugin_runtime_observability_plugin_watch_surfaces(
        lane_id: &str,
    ) -> Vec<&'static str> {
        match lane_id {
            "browser_webpreview" => vec![
                "editor caret and typing latency",
                "WebPreview focus after navigation or reload",
                "native click/type/key/scroll/history/cache receipts",
                "manual final validation result evidence",
            ],
            "managed_chrome" => vec![
                "managed workspace or Zed-data roots only",
                "real Chrome, Edge, and Firefox profiles stay untouched",
                "safe Playwright action execution receipts",
                "click, type, key, and scroll stay blocked in the managed adapter",
            ],
            "pc_use" => vec![
                "future UI snapshot target ids require matching snapshot receipt ids",
                "runner receipts stay auditable before any future executor exists",
                "no focus, click, type, screenshot, or process launch in the current gate",
                "OS-wide desktop control stays blocked by default",
            ],
            _ => Vec::new(),
        }
    }

    fn agent_plugin_runtime_green_proof_path(&self, window: &Window) -> Value {
        let handoff = self.agent_plugin_runtime_green_operator_handoff(window);
        let digest = self.agent_plugin_runtime_observability_digest_from_handoff(&handoff);
        self.agent_plugin_runtime_green_proof_path_from_packets(&handoff, &digest)
    }

    fn agent_plugin_runtime_green_proof_path_from_packets(
        &self,
        handoff: &Value,
        digest: &Value,
    ) -> Value {
        let root_mode = handoff
            .get("root_mode")
            .and_then(Value::as_str)
            .unwrap_or("workspace");
        let runtime_green_candidate = handoff
            .get("runtime_green_candidate")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let lane_count = handoff
            .pointer("/summary/lane_count")
            .and_then(Value::as_u64)
            .unwrap_or_default();
        let ready_lane_count = handoff
            .pointer("/summary/ready_lane_count")
            .and_then(Value::as_u64)
            .unwrap_or_default();
        let pending_lane_count = digest
            .pointer("/summary/pending_lane_count")
            .and_then(Value::as_u64)
            .unwrap_or_else(|| lane_count.saturating_sub(ready_lane_count));
        let final_result_summary = self.latest_agent_browser_final_validation_result_summary();
        let final_result_imported = final_result_summary.is_some();
        let final_result_runtime_green = final_result_summary
            .as_ref()
            .and_then(|summary| summary.get("runtime_green_candidate"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let current_best_next = handoff
            .get("current_best_next")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({}));
        let current_best_next_lane = current_best_next
            .get("lane_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown")
            .to_string();
        let current_best_next_label = current_best_next
            .get("label")
            .and_then(Value::as_str)
            .unwrap_or(&current_best_next_lane)
            .to_string();
        let current_best_next_status = current_best_next
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown")
            .to_string();
        let claim_gate_ready = runtime_green_candidate && final_result_runtime_green;
        let claim_gate_status = if claim_gate_ready {
            "ready"
        } else if !final_result_imported {
            "missing_final_validation_result"
        } else if pending_lane_count > 0 {
            "pending_runtime_evidence"
        } else {
            "manual_review_required"
        };

        serde_json::json!({
            "schema": AGENT_PLUGIN_RUNTIME_GREEN_PROOF_PATH_SCHEMA,
            "generated_at_ms": Self::current_epoch_millis(),
            "source": "web_preview",
            "status": if runtime_green_candidate {
                "runtime_green_candidate"
            } else {
                "operator_action_required"
            },
            "runtime_green_candidate": runtime_green_candidate,
            "root_mode": root_mode,
            "session": handoff
                .get("session")
                .cloned()
                .unwrap_or_else(|| serde_json::json!({})),
            "summary": {
                "lane_count": lane_count,
                "ready_lane_count": ready_lane_count,
                "pending_lane_count": pending_lane_count,
                "current_best_next_lane": handoff.pointer("/summary/current_best_next_lane").and_then(Value::as_str),
                "final_result_imported": final_result_imported,
                "final_result_runtime_green": final_result_runtime_green,
            },
            "claim_gate": {
                "ready_lane_count": ready_lane_count,
                "lane_count": lane_count,
                "all_lanes_ready": pending_lane_count == 0 && lane_count > 0,
                "final_browser_result_imported": final_result_imported,
                "final_browser_result_runtime_green": final_result_runtime_green,
                "can_claim_runtime_green_from_webpreview": claim_gate_ready,
                "manual_runtime_command": "just run"
            },
            "operator_summary": {
                "status": claim_gate_status,
                "ready_lane_fraction": format!("{ready_lane_count}/{lane_count}"),
                "pending_lane_count": pending_lane_count,
                "first_pending_lane_id": current_best_next_lane,
                "first_pending_lane_label": current_best_next_label,
                "first_pending_lane_status": current_best_next_status,
                "can_claim_runtime_green_from_webpreview": claim_gate_ready,
                "next_operator_step": if claim_gate_ready {
                    "Run the final manual Windows runtime proof before reporting runtime-green."
                } else {
                    "Resolve the first pending evidence lane, then re-read the proof path."
                }
            },
            "current_digest": Self::agent_plugin_runtime_observability_digest_summary(digest),
            "current_operator_handoff": Self::agent_plugin_runtime_green_operator_handoff_summary(handoff),
            "current_best_next": current_best_next,
            "proof_sources": {
                "final_validation_observability": handoff
                    .pointer("/webpreview_evidence/final_validation_observability")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!({})),
                "final_validation_result_summary": final_result_summary,
                "plugin_bootstrap_readiness": handoff
                    .pointer("/webpreview_evidence/plugin_bootstrap_readiness")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!({})),
                "managed_chrome_execution_status": handoff
                    .pointer("/webpreview_evidence/managed_chrome_execution_status")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!({})),
                "pc_use_status": handoff
                    .pointer("/webpreview_evidence/pc_use_status")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!({})),
            },
            "agent_runtime_status_tool": {
                "tool_name": "inspect_agent_plugin_runtime_status",
                "schema": "zed.agent_plugins.runtime_status.v1",
                "proof_path_schema": AGENT_PLUGIN_RUNTIME_GREEN_PROOF_PATH_SCHEMA,
                "payload": runtime_green_status_payload(root_mode)
            },
            "agent_read_sequence": [
                {
                    "step": "read_webpreview_proof_path",
                    "copy_action": "copy_agent_plugin_runtime_green_proof_path",
                    "send_action": "send_agent_plugin_runtime_green_proof_path_to_agent",
                    "purpose": "Start from the compact proof path before expanding into larger packets."
                },
                {
                    "step": "inspect_agent_runtime_status",
                    "tool_name": "inspect_agent_plugin_runtime_status",
                    "payload": runtime_green_status_payload(root_mode),
                    "purpose": "Read the canonical Agent-side proof path and managed proof-file locations."
                },
                {
                    "step": "follow_current_best_next",
                    "field": "current_best_next",
                    "purpose": "Resolve the first pending runtime-green lane before claiming readiness."
                },
                {
                    "step": "import_final_result_when_available",
                    "action": "import_agent_browser_final_validation_result_from_clipboard",
                    "purpose": "Persist the final manual Windows result before any runtime-green claim."
                }
            ],
            "webpreview_packets": {
                "runtime_green_proof_path": {
                    "schema": AGENT_PLUGIN_RUNTIME_GREEN_PROOF_PATH_SCHEMA,
                    "copy_action": "copy_agent_plugin_runtime_green_proof_path",
                    "send_action": "send_agent_plugin_runtime_green_proof_path_to_agent"
                },
                "runtime_observability_digest": {
                    "schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_DIGEST_SCHEMA,
                    "plugin_matrix_schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_MATRIX_SCHEMA,
                    "regression_watch_rollup_schema": AGENT_PLUGIN_RUNTIME_OBSERVABILITY_WATCH_ROLLUP_SCHEMA,
                    "copy_action": "copy_agent_plugin_runtime_observability_digest",
                    "send_action": "send_agent_plugin_runtime_observability_digest_to_agent"
                },
                "runtime_green_operator_handoff": {
                    "schema": AGENT_PLUGIN_RUNTIME_GREEN_OPERATOR_HANDOFF_SCHEMA,
                    "copy_action": "copy_agent_plugin_runtime_green_handoff",
                    "send_action": "send_agent_plugin_runtime_green_handoff_to_agent"
                }
            },
            "reads_from": [
                "runtime_observability_digest",
                "runtime_green_operator_handoff",
                "final_validation_observability",
                "managed_chrome_execution_status",
                "pc_use_status"
            ],
            "safety": {
                "read_only": true,
                "writes_files": false,
                "runs_node": false,
                "launches_browser": false,
                "dispatches_input": false,
                "touches_real_browser_profiles": false
            }
        })
    }

    fn agent_plugin_runtime_green_proof_path_summary(proof_path: &Value) -> Value {
        serde_json::json!({
            "schema": proof_path.get("schema").and_then(Value::as_str),
            "status": proof_path.get("status").and_then(Value::as_str),
            "runtime_green_candidate": proof_path.get("runtime_green_candidate").and_then(Value::as_bool),
            "root_mode": proof_path.get("root_mode").and_then(Value::as_str),
            "ready_lane_count": proof_path.pointer("/summary/ready_lane_count").and_then(Value::as_u64),
            "lane_count": proof_path.pointer("/summary/lane_count").and_then(Value::as_u64),
            "pending_lane_count": proof_path.pointer("/summary/pending_lane_count").and_then(Value::as_u64),
            "current_best_next_lane": proof_path.pointer("/summary/current_best_next_lane").and_then(Value::as_str),
            "first_pending_lane_label": proof_path.pointer("/operator_summary/first_pending_lane_label").and_then(Value::as_str),
            "claim_gate_status": proof_path.pointer("/operator_summary/status").and_then(Value::as_str),
            "can_claim_runtime_green_from_webpreview": proof_path.pointer("/claim_gate/can_claim_runtime_green_from_webpreview").and_then(Value::as_bool),
        })
    }

    fn agent_plugin_runtime_green_proof_path_json(proof_path: &Value) -> String {
        serde_json::to_string_pretty(proof_path).unwrap_or_else(|_| "{}".to_string())
    }

    fn agent_plugin_runtime_green_proof_path_agent_summary(proof_path: &Value) -> String {
        let status = proof_path
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let ready_lane_count = proof_path
            .pointer("/summary/ready_lane_count")
            .and_then(Value::as_u64)
            .unwrap_or(0);
        let lane_count = proof_path
            .pointer("/summary/lane_count")
            .and_then(Value::as_u64)
            .unwrap_or(0);
        let first_pending_lane = proof_path
            .pointer("/operator_summary/first_pending_lane_label")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let first_pending_status = proof_path
            .pointer("/operator_summary/first_pending_lane_status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let claim_gate_status = proof_path
            .pointer("/operator_summary/status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let can_claim_runtime_green = proof_path
            .pointer("/claim_gate/can_claim_runtime_green_from_webpreview")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let next_step = proof_path
            .pointer("/operator_summary/next_operator_step")
            .and_then(Value::as_str)
            .unwrap_or("Re-read the runtime-green proof path.");

        format!(
            "Runtime-green proof path\nStatus: {status}\nReady lanes: {ready_lane_count}/{lane_count}\nFirst pending evidence: {first_pending_lane} ({first_pending_status})\nClaim gate: {claim_gate_status} (can claim: {can_claim_runtime_green})\nNext: {next_step}"
        )
    }

    fn agent_plugin_runtime_green_proof_path_agent_blocks(
        &self,
        proof_path: &Value,
    ) -> Vec<acp::ContentBlock> {
        let mut blocks = Vec::new();
        if let Some(url) = proof_path
            .pointer("/session/page/url")
            .and_then(Value::as_str)
            && let Some(url_block) = self.url_attachment_block(url)
        {
            blocks.push(url_block);
            blocks.push(acp::ContentBlock::Text(acp::TextContent::new("\n\n")));
        }

        blocks.push(acp::ContentBlock::Text(acp::TextContent::new(format!(
            "{}\n\n```json\n{}\n```",
            Self::agent_plugin_runtime_green_proof_path_agent_summary(proof_path),
            Self::agent_plugin_runtime_green_proof_path_json(proof_path)
        ))));
        blocks
    }

    fn copy_agent_plugin_runtime_green_proof_path(
        &mut self,
        window: &Window,
        cx: &mut Context<Self>,
    ) {
        let proof_path = self.agent_plugin_runtime_green_proof_path(window);
        cx.write_to_clipboard(ClipboardItem::new_string(
            Self::agent_plugin_runtime_green_proof_path_json(&proof_path),
        ));
        self.show_toast("Copied runtime-green proof path", cx);
        cx.notify();
    }

    fn send_agent_plugin_runtime_green_proof_path_to_agent(
        &mut self,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        let proof_path = self.agent_plugin_runtime_green_proof_path(window);
        let blocks = self.agent_plugin_runtime_green_proof_path_agent_blocks(&proof_path);
        self.append_content_blocks_to_agent_panel(blocks, window, cx);
        self.show_toast("Sent runtime-green proof path to the agent panel", cx);
        cx.notify();
    }

    fn agent_plugin_runtime_green_claim_gate_json(claim_gate: &Value) -> String {
        serde_json::to_string_pretty(claim_gate).unwrap_or_else(|_| "{}".to_string())
    }

    fn agent_plugin_runtime_green_claim_gate_agent_summary(claim_gate: &Value) -> String {
        let status = claim_gate
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let ready_lane_fraction = claim_gate
            .get("ready_lane_fraction")
            .and_then(Value::as_str)
            .unwrap_or("0/0");
        let first_pending_lane = claim_gate
            .get("first_pending_lane_label")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let first_pending_status = claim_gate
            .get("first_pending_lane_status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let can_claim_runtime_green = claim_gate
            .get("can_claim_runtime_green_from_webpreview")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let next_step = claim_gate
            .get("next_operator_step")
            .and_then(Value::as_str)
            .unwrap_or("Re-read the runtime-green claim gate.");
        let required_proof = claim_gate
            .pointer("/next_required_proof/required_proof_id")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let recommended_action = claim_gate
            .pointer("/next_required_proof/recommended_action")
            .and_then(Value::as_str)
            .unwrap_or("copy_agent_plugin_runtime_green_claim_gate");
        let final_checklist_status = claim_gate
            .pointer("/final_operator_checklist/status")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let final_can_run = claim_gate
            .pointer("/final_operator_checklist/can_run_final_manual_command")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let final_required_proof = claim_gate
            .pointer("/final_operator_checklist/first_required_proof_id")
            .and_then(Value::as_str)
            .unwrap_or(required_proof);

        format!(
            "Runtime-green claim gate\nStatus: {status}\nReady lanes: {ready_lane_fraction}\nFirst pending evidence: {first_pending_lane} ({first_pending_status})\nRequired proof: {required_proof}\nRecommended action: {recommended_action}\nFinal checklist: {final_checklist_status} (can run final command: {final_can_run}, first proof: {final_required_proof})\nCan claim from WebPreview: {can_claim_runtime_green}\nNext: {next_step}"
        )
    }

    fn agent_plugin_runtime_green_claim_gate_agent_blocks(
        &self,
        claim_gate: &Value,
    ) -> Vec<acp::ContentBlock> {
        vec![acp::ContentBlock::Text(acp::TextContent::new(format!(
            "{}\n\n```json\n{}\n```",
            Self::agent_plugin_runtime_green_claim_gate_agent_summary(claim_gate),
            Self::agent_plugin_runtime_green_claim_gate_json(claim_gate)
        )))]
    }

