    fn current_epoch_millis() -> u64 {
        SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|duration| duration.as_millis().min(u64::MAX as u128) as u64)
            .unwrap_or_default()
    }

    fn agent_browser_executor_gate(&self) -> AgentBrowserExecutorGate {
        let context_ready = self.latest_page_diagnostics.is_some()
            && self.latest_dom_snapshot.is_some()
            && self.latest_action_targets.is_some()
            && self.latest_readiness_probe.is_some();
        let audit_ready = self.latest_wait_contract.is_some()
            && self.latest_interaction_plan.is_some()
            && self.latest_interaction_preflight.is_some()
            && self.latest_interaction_receipt_template.is_some()
            && self.latest_interaction_action_request.is_some()
            && self.latest_blocked_interaction_receipt.is_some()
            && self.latest_successful_interaction_receipt.is_some();

        AgentBrowserExecutorGate {
            interactive_unlocked: self.agent_action_permission.interactive_enabled(),
            context_ready,
            audit_ready,
        }
    }

    fn agent_browser_executor_gate_blockers(
        &self,
        gate: AgentBrowserExecutorGate,
        context_message: &'static str,
        audit_message: &'static str,
    ) -> Vec<Value> {
        let mut blockers = Vec::new();
        if !gate.interactive_unlocked {
            blockers.push(serde_json::json!({
                "code": "interactive_actions_locked",
                "message": "Interactive Agent Browser actions are locked for this WebPreview session.",
            }));
        }
        if !gate.context_ready {
            blockers.push(serde_json::json!({
                "code": "context_not_collected",
                "message": context_message,
            }));
        }
        if !gate.audit_ready {
            blockers.push(serde_json::json!({
                "code": "audit_contract_incomplete",
                "message": audit_message,
            }));
        }
        blockers
    }

    fn permissioned_executor_receipt(
        &self,
        schema: &'static str,
        action: &'static str,
        outcome: &'static str,
        gate: AgentBrowserExecutorGate,
        before: Value,
        after: Value,
        blockers: Vec<Value>,
        dispatch_error: Option<String>,
        browser_command_dispatched: bool,
        native_input_dispatched: bool,
        page_script_dispatched: bool,
        gate_extra_fields: Vec<(&'static str, Value)>,
        receipt_extra_fields: Vec<(&'static str, Value)>,
    ) -> Value {
        let mut gate_object = serde_json::Map::new();
        gate_object.insert(
            "interactive_unlocked".to_string(),
            serde_json::json!(gate.interactive_unlocked),
        );
        gate_object.insert(
            "context_ready".to_string(),
            serde_json::json!(gate.context_ready),
        );
        gate_object.insert(
            "audit_ready".to_string(),
            serde_json::json!(gate.audit_ready),
        );
        gate_object.insert(
            "gate_ready_for_executor".to_string(),
            serde_json::json!(gate.ready_for_executor()),
        );
        for (key, value) in gate_extra_fields {
            gate_object.insert(key.to_string(), value);
        }

        let mut receipt = serde_json::Map::new();
        receipt.insert("schema".to_string(), serde_json::json!(schema));
        receipt.insert(
            "timestamp_ms".to_string(),
            serde_json::json!(Self::current_epoch_millis()),
        );
        receipt.insert("action".to_string(), serde_json::json!(action));
        receipt.insert("outcome".to_string(), serde_json::json!(outcome));
        receipt.insert(
            "session_id".to_string(),
            serde_json::json!(self.session_id.as_ref()),
        );
        receipt.insert(
            "url".to_string(),
            serde_json::json!(self.active_url.as_ref()),
        );
        receipt.insert(
            "title".to_string(),
            serde_json::json!(self.current_tab_title().as_ref()),
        );
        receipt.insert(
            "permission".to_string(),
            self.agent_action_permission.snapshot(),
        );
        receipt.insert("gate".to_string(), Value::Object(gate_object));
        for (key, value) in receipt_extra_fields {
            receipt.insert(key.to_string(), value);
        }
        receipt.insert("before".to_string(), before);
        receipt.insert("after".to_string(), after);
        receipt.insert("blockers".to_string(), Value::Array(blockers));
        receipt.insert(
            "dispatch_error".to_string(),
            dispatch_error.map_or(Value::Null, Value::String),
        );
        receipt.insert(
            "browser_command_dispatched".to_string(),
            serde_json::json!(browser_command_dispatched),
        );
        receipt.insert(
            "native_input_dispatched".to_string(),
            serde_json::json!(native_input_dispatched),
        );
        receipt.insert(
            "page_script_dispatched".to_string(),
            serde_json::json!(page_script_dispatched),
        );

        Value::Object(receipt)
    }

    fn first_action_target(&self, action_kind: &'static str) -> Option<Value> {
        self.latest_action_targets
            .as_ref()?
            .pointer("/targets/targets")?
            .as_array()?
            .iter()
            .find(|target| {
                target.pointer("/action_kind").and_then(Value::as_str) == Some(action_kind)
                    && target
                        .pointer("/visible")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                    && !target
                        .pointer("/disabled")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                    && target
                        .pointer("/selector")
                        .and_then(Value::as_str)
                        .is_some_and(|selector| !selector.trim().is_empty())
            })
            .cloned()
    }

    fn first_click_action_target(&self) -> Option<Value> {
        self.first_action_target("click")
    }

    fn first_type_action_target(&self) -> Option<Value> {
        self.first_action_target("type")
    }

    fn first_scroll_action_target(&self) -> Option<Value> {
        if let Some(target) = self
            .latest_interaction_plan
            .as_ref()
            .and_then(|plan| plan.pointer("/plan/action_groups"))
            .and_then(Value::as_array)
            .and_then(|groups| {
                groups.iter().find(|group| {
                    group.pointer("/action").and_then(Value::as_str) == Some("scroll")
                })
            })
            .and_then(|group| group.pointer("/targets"))
            .and_then(Value::as_array)
            .and_then(|targets| targets.first())
            .cloned()
        {
            return Some(target);
        }

        let viewport = self
            .latest_page_diagnostics
            .as_ref()
            .and_then(|page| page.pointer("/page/viewport"))?;
        let inner_height = viewport.pointer("/inner_height").and_then(Value::as_u64)?;
        let scroll_height = viewport.pointer("/scroll_height").and_then(Value::as_u64)?;
        if scroll_height <= inner_height {
            return None;
        }

        Some(serde_json::json!({
            "selector": "window",
            "tag": "window",
            "label": "Page viewport",
            "rect": null,
            "scroll_x": viewport.pointer("/scroll_x").cloned(),
            "scroll_y": viewport.pointer("/scroll_y").cloned(),
            "inner_height": inner_height,
            "scroll_height": scroll_height,
        }))
    }

    fn key_preflight_candidate(&self) -> Value {
        serde_json::json!({
            "key": "Escape",
            "reason": "Safe default planning key; no key event is dispatched by this preflight.",
            "allowed_examples": ["Escape", "Enter", "Tab", "ArrowDown", "ArrowUp"],
            "active_element": self.latest_action_targets
                .as_ref()
                .and_then(|targets| targets.pointer("/targets/active_element"))
                .cloned(),
        })
    }

    fn load_state_name(&self) -> &'static str {
        match &self.load_state {
            PreviewLoadState::Loading => "loading",
            PreviewLoadState::Ready => "ready",
            PreviewLoadState::Error(_) => "error",
        }
    }

    fn viewport_label(&self) -> String {
        match self.viewport_mode.dimensions() {
            Some((width, height)) => {
                format!("{} ({}x{})", self.viewport_mode.label(), width, height)
            }
            None => self.viewport_mode.label().to_string(),
        }
    }

    fn browser_session_json(&self, window: &Window) -> String {
        serde_json::to_string_pretty(&self.browser_session_snapshot(window))
            .unwrap_or_else(|_| "{}".to_string())
    }

    fn workspace_session_snapshots(&self, window: &Window, cx: &App) -> Vec<Value> {
        let Some(workspace) = self.workspace.upgrade() else {
            return vec![self.browser_session_snapshot(window)];
        };

        let mut snapshots = workspace.read_with(cx, |workspace, cx| {
            workspace
                .items(cx)
                .filter_map(|item| {
                    let preview = item.downcast::<WebPreviewView>()?;
                    Some(preview.read(cx).browser_session_snapshot(window))
                })
                .collect::<Vec<_>>()
        });

        if snapshots.is_empty() {
            snapshots.push(self.browser_session_snapshot(window));
        }

        snapshots
    }

    fn workspace_session_inventory_json(&self, window: &Window, cx: &App) -> String {
        let sessions = self.workspace_session_snapshots(window, cx);
        let inventory = serde_json::json!({
            "schema": "zed.web_preview.session_inventory.v1",
            "active_session_id": self.session_id.as_ref(),
            "count": sessions.len(),
            "sessions": sessions,
        });

        serde_json::to_string_pretty(&inventory).unwrap_or_else(|_| "{}".to_string())
    }

