fn managed_chrome_execution_next_actions(status: &str) -> Vec<&'static str> {
    match status {
        "has_recent_execution_receipt" => vec![
            "Send this status to the Agent Panel when the agent needs the latest external Chrome outcome.",
            "Inspect the receipt error, screenshot artifact, runtime events, DOM snapshot, or element inspection summary before queueing another managed Chrome action.",
        ],
        "has_request_without_receipt" => vec![
            "Invoke the prepared Playwright adapter after runner-gate readiness passes.",
            "If invocation already ran, check why the adapter did not write an execution receipt.",
        ],
        _ => vec![
            "Queue a managed Chrome action, request the runner gate, prepare the adapter, then invoke a safe action.",
        ],
    }
}

fn latest_pc_use_status_file(
    roots: &[PcUseStatusRoot],
    kind: PcUseStatusFileKind,
    expected_schema: &str,
) -> Option<Value> {
    let mut latest: Option<(u64, String, Value)> = None;
    for root in roots {
        let directory_path = match kind {
            PcUseStatusFileKind::PayloadQueue => &root.payload_dir,
            PcUseStatusFileKind::RunnerReceipt => &root.receipt_dir,
        };
        let Ok(entries) = fs::read_dir(directory_path) else {
            continue;
        };
        for entry in entries.flatten() {
            let path = entry.path();
            if !path.starts_with(directory_path)
                || path.extension().and_then(|extension| extension.to_str()) != Some("json")
            {
                continue;
            }
            let Some(file_name) = path.file_name().and_then(|name| name.to_str()) else {
                continue;
            };
            let matches_kind = match kind {
                PcUseStatusFileKind::PayloadQueue => file_name == PC_USE_PAYLOAD_QUEUE_FILE_NAME,
                PcUseStatusFileKind::RunnerReceipt => {
                    file_name == PC_USE_RUNNER_RECEIPT_FILE_NAME
                        || file_name.starts_with(PC_USE_RUNNER_RECEIPT_PREFIX)
                }
            };
            if !matches_kind {
                continue;
            }

            let metadata = entry.metadata().ok();
            let modified_ms = metadata
                .as_ref()
                .and_then(|metadata| metadata.modified().ok())
                .and_then(system_time_ms)
                .unwrap_or_default();
            let bytes = metadata.map(|metadata| metadata.len()).unwrap_or_default();
            let summary = serde_json::json!({
                "root_kind": root.kind,
                "path": path.display().to_string(),
                "file_name": file_name,
                "modified_at_ms": modified_ms,
                "bytes": bytes,
                "kind": match kind {
                    PcUseStatusFileKind::PayloadQueue => "payload_queue",
                    PcUseStatusFileKind::RunnerReceipt => "runner_receipt",
                },
                "read": pc_use_status_file_read_summary(&path, expected_schema, kind),
            });

            let replace = match latest.as_ref() {
                None => true,
                Some((latest_modified_ms, latest_file_name, _)) => {
                    modified_ms > *latest_modified_ms
                        || (modified_ms == *latest_modified_ms
                            && file_name > latest_file_name.as_str())
                }
            };
            if replace {
                latest = Some((modified_ms, file_name.to_string(), summary));
            }
        }
    }

    latest.map(|(_, _, summary)| summary)
}

fn pc_use_status_file_read_summary(
    path: &Path,
    expected_schema: &str,
    kind: PcUseStatusFileKind,
) -> Value {
    let bytes = match fs::read(path) {
        Ok(bytes) => bytes,
        Err(error) => {
            return serde_json::json!({
                "ok": false,
                "state": "read_error",
                "details": error.to_string(),
            });
        }
    };
    let value = match serde_json::from_slice::<Value>(&bytes) {
        Ok(value) => value,
        Err(error) => {
            return serde_json::json!({
                "ok": false,
                "state": "parse_error",
                "bytes": bytes.len(),
                "details": error.to_string(),
            });
        }
    };
    let schema = value
        .get("schema")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let schema_ok = schema == expected_schema;
    let payload_schema = value
        .pointer("/payload_packet/schema")
        .and_then(Value::as_str);
    let payload_schema_ok = payload_schema == Some(PC_USE_PAYLOAD_SCHEMA);
    let dispatches_input = value
        .pointer("/payload_packet/safety/dispatches_input")
        .and_then(Value::as_bool)
        .unwrap_or(kind == PcUseStatusFileKind::RunnerReceipt);

    serde_json::json!({
        "ok": true,
        "state": if schema_ok { "ready" } else { "schema_mismatch" },
        "bytes": bytes.len(),
        "schema": schema,
        "schema_ok": schema_ok,
        "payload_schema": payload_schema,
        "payload_schema_ok": payload_schema_ok,
        "generated_at_ms": value.pointer("/result/generated_at_ms")
            .or_else(|| value.get("queued_at_ms"))
            .cloned(),
        "outcome": value.pointer("/result/outcome").and_then(Value::as_str),
        "action": value.pointer("/queue/action").and_then(Value::as_str)
            .or_else(|| value.pointer("/payload_packet/payload/action").and_then(Value::as_str)),
        "surface": value.pointer("/queue/surface").and_then(Value::as_str)
            .or_else(|| value.pointer("/payload_packet/payload/surface").and_then(Value::as_str)),
        "target_id_present": value.pointer("/queue/target_id_present").and_then(Value::as_bool)
            .or_else(|| value.pointer("/payload_packet/payload/target_id").and_then(Value::as_str).map(|target_id| !target_id.trim().is_empty())),
        "target_snapshot_id": value.pointer("/queue/target_snapshot_id").and_then(Value::as_str)
            .or_else(|| value.pointer("/payload_packet/payload/target_snapshot_id").and_then(Value::as_str)),
        "target_snapshot_id_present": value.pointer("/queue/target_snapshot_id_present").and_then(Value::as_bool)
            .or_else(|| value.pointer("/payload_packet/payload/target_snapshot_id").and_then(Value::as_str).map(|snapshot_id| !snapshot_id.trim().is_empty())),
        "target_reference": value.pointer("/queue/target_reference").cloned()
            .or_else(|| value.pointer("/payload_packet/payload/target_reference").cloned()),
        "queue_blocker_count": value.pointer("/queue_blockers").and_then(Value::as_array).map(Vec::len),
        "executor_pending_count": value.pointer("/executor_pending").and_then(Value::as_array).map(Vec::len),
        "future_executor_pending": kind == PcUseStatusFileKind::RunnerReceipt
            && value.pointer("/result/outcome").and_then(Value::as_str) == Some("ready_future_executor_pending"),
        "future_executor_enabled": value.pointer("/result/future_executor_enabled").and_then(Value::as_bool),
        "safe_for_handoff": kind == PcUseStatusFileKind::PayloadQueue && schema_ok && payload_schema_ok && !dispatches_input,
        "dispatches_input": dispatches_input,
        "takes_screenshot": value.pointer("/payload_packet/safety/takes_screenshot").and_then(Value::as_bool)
            .or_else(|| value.pointer("/safety/takes_screenshot").and_then(Value::as_bool)),
        "focuses_zed": value.pointer("/safety/focuses_zed").and_then(Value::as_bool)
            .or_else(|| value.pointer("/payload_packet/safety/focuses_window").and_then(Value::as_bool)),
        "dispatches_mouse": value.pointer("/safety/dispatches_mouse").and_then(Value::as_bool),
        "dispatches_keyboard": value.pointer("/safety/dispatches_keyboard").and_then(Value::as_bool),
        "launches_process": value.pointer("/safety/launches_process").and_then(Value::as_bool)
            .or_else(|| value.pointer("/payload_packet/safety/launches_process").and_then(Value::as_bool)),
        "os_wide_control": value.pointer("/payload_packet/safety/os_wide_control").and_then(Value::as_bool),
        "os_wide_desktop_control": value.pointer("/safety/os_wide_desktop_control").and_then(Value::as_bool),
        "source_tool": value.get("source_tool").and_then(Value::as_str),
    })
}

fn pc_use_status_proof_summary(
    status: &str,
    latest_outcome: &str,
    latest_queue: Option<&Value>,
    latest_receipt: Option<&Value>,
) -> Value {
    let queue_read = latest_queue.and_then(|queue| queue.get("read"));
    let receipt_read = latest_receipt.and_then(|receipt| receipt.get("read"));
    let queue_ready = queue_read
        .and_then(|read| read.get("safe_for_handoff"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let receipt_ready = receipt_read
        .and_then(|read| read.get("future_executor_pending"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let proof_status = if receipt_ready {
        "ready_future_executor_receipt_present"
    } else if latest_receipt.is_some() {
        "runner_receipt_not_ready"
    } else if queue_ready {
        "payload_ready_runner_receipt_missing"
    } else if latest_queue.is_some() {
        "payload_not_ready"
    } else {
        "payload_missing"
    };

    serde_json::json!({
        "schema": PC_USE_PROOF_SUMMARY_SCHEMA,
        "status": proof_status,
        "webpreview_status": status,
        "latest_outcome": latest_outcome,
        "ready": receipt_ready,
        "payload_ready": queue_ready,
        "runner_receipt_ready": receipt_ready,
        "payload": {
            "root_kind": latest_queue.and_then(|queue| queue.get("root_kind")).and_then(Value::as_str),
            "path": latest_queue.and_then(|queue| queue.get("path")).and_then(Value::as_str),
            "modified_at_ms": latest_queue.and_then(|queue| queue.get("modified_at_ms")).and_then(Value::as_u64),
            "schema": queue_read.and_then(|read| read.get("schema")).and_then(Value::as_str),
            "payload_schema": queue_read.and_then(|read| read.get("payload_schema")).and_then(Value::as_str),
            "action": queue_read.and_then(|read| read.get("action")).and_then(Value::as_str),
            "surface": queue_read.and_then(|read| read.get("surface")).and_then(Value::as_str),
            "target_id_present": queue_read.and_then(|read| read.get("target_id_present")).and_then(Value::as_bool),
            "target_snapshot_id": queue_read.and_then(|read| read.get("target_snapshot_id")).and_then(Value::as_str),
            "target_snapshot_id_present": queue_read.and_then(|read| read.get("target_snapshot_id_present")).and_then(Value::as_bool),
            "target_reference": queue_read.and_then(|read| read.get("target_reference")).cloned(),
            "safe_for_handoff": queue_ready,
        },
        "runner_receipt": {
            "root_kind": latest_receipt.and_then(|receipt| receipt.get("root_kind")).and_then(Value::as_str),
            "path": latest_receipt.and_then(|receipt| receipt.get("path")).and_then(Value::as_str),
            "modified_at_ms": latest_receipt.and_then(|receipt| receipt.get("modified_at_ms")).and_then(Value::as_u64),
            "schema": receipt_read.and_then(|read| read.get("schema")).and_then(Value::as_str),
            "outcome": receipt_read.and_then(|read| read.get("outcome")).and_then(Value::as_str),
            "action": receipt_read.and_then(|read| read.get("action")).and_then(Value::as_str),
            "surface": receipt_read.and_then(|read| read.get("surface")).and_then(Value::as_str),
            "target_id_present": receipt_read.and_then(|read| read.get("target_id_present")).and_then(Value::as_bool),
            "target_snapshot_id": receipt_read.and_then(|read| read.get("target_snapshot_id")).and_then(Value::as_str),
            "target_snapshot_id_present": receipt_read.and_then(|read| read.get("target_snapshot_id_present")).and_then(Value::as_bool),
            "target_reference": receipt_read.and_then(|read| read.get("target_reference")).cloned(),
            "queue_blocker_count": receipt_read.and_then(|read| read.get("queue_blocker_count")).and_then(Value::as_u64),
            "executor_pending_count": receipt_read.and_then(|read| read.get("executor_pending_count")).and_then(Value::as_u64),
            "future_executor_enabled": receipt_read.and_then(|read| read.get("future_executor_enabled")).and_then(Value::as_bool),
        },
        "next_actions": pc_use_status_next_actions(status, latest_outcome),
        "safety": {
            "summary_is_read_only": true,
            "writes_files": false,
            "takes_screenshot": false,
            "focuses_zed": false,
            "dispatches_input": false,
            "launches_processes": false,
            "os_wide_desktop_control": false,
        },
    })
}

fn pc_use_status_proof_card(
    status: &str,
    latest_outcome: &str,
    latest_queue: Option<&Value>,
    latest_receipt: Option<&Value>,
    proof_summary: &Value,
) -> Value {
    let proof_status = proof_summary
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let ready = proof_summary
        .get("ready")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let payload_ready = proof_summary
        .get("payload_ready")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let runner_receipt_ready = proof_summary
        .get("runner_receipt_ready")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let source = latest_receipt
        .and_then(|receipt| receipt.get("read"))
        .or_else(|| latest_queue.and_then(|queue| queue.get("read")));
    let state = match (status, proof_status) {
        ("has_ready_runner_receipt", _) => "runner_receipt_ready",
        ("has_blocked_runner_receipt", _) => "runner_receipt_blocked",
        ("has_queue_without_receipt", "payload_ready_runner_receipt_missing") => {
            "payload_ready_runner_receipt_missing"
        }
        ("has_queue_without_receipt", _) => "payload_not_ready",
        _ => "empty",
    };

    serde_json::json!({
        "schema": PC_USE_PROOF_CARD_SCHEMA,
        "source_schema": PC_USE_PROOF_SUMMARY_SCHEMA,
        "state": state,
        "status": status,
        "proof_status": proof_status,
        "latest_outcome": latest_outcome,
        "ready": ready,
        "payload_ready": payload_ready,
        "runner_receipt_ready": runner_receipt_ready,
        "action": source.and_then(|read| read.get("action")).and_then(Value::as_str),
        "surface": source.and_then(|read| read.get("surface")).and_then(Value::as_str),
        "target": {
            "target_id_present": source.and_then(|read| read.get("target_id_present")).and_then(Value::as_bool),
            "target_snapshot_id": source.and_then(|read| read.get("target_snapshot_id")).and_then(Value::as_str),
            "target_snapshot_id_present": source.and_then(|read| read.get("target_snapshot_id_present")).and_then(Value::as_bool),
            "target_reference": source.and_then(|read| read.get("target_reference")).cloned(),
        },
        "payload_file": pc_use_status_proof_card_file(latest_queue),
        "runner_receipt_file": pc_use_status_proof_card_file(latest_receipt),
        "blockers": {
            "queue_blocker_count": proof_summary
                .pointer("/runner_receipt/queue_blocker_count")
                .and_then(Value::as_u64)
                .or_else(|| source.and_then(|read| read.get("queue_blocker_count")).and_then(Value::as_u64)),
            "executor_pending_count": proof_summary
                .pointer("/runner_receipt/executor_pending_count")
                .and_then(Value::as_u64)
                .or_else(|| source.and_then(|read| read.get("executor_pending_count")).and_then(Value::as_u64)),
        },
        "next_action": pc_use_status_proof_card_next_action(status, latest_outcome),
        "summary": {
            "payload": proof_summary.get("payload").cloned(),
            "runner_receipt": proof_summary.get("runner_receipt").cloned(),
        },
        "safety": {
            "read_only": true,
            "writes_files": false,
            "takes_screenshot": false,
            "focuses_zed": false,
            "dispatches_mouse": false,
            "dispatches_keyboard": false,
            "dispatches_input": false,
            "launches_process": false,
            "os_wide_desktop_control": false,
            "managed_roots_only": true,
            "future_executor_required_before_input": true,
        },
    })
}

fn pc_use_status_proof_card_file(file: Option<&Value>) -> Option<Value> {
    let file = file?;
    Some(serde_json::json!({
        "root_kind": file.get("root_kind").and_then(Value::as_str),
        "path": file.get("path").and_then(Value::as_str),
        "file_name": file.get("file_name").and_then(Value::as_str),
        "modified_at_ms": file.get("modified_at_ms").and_then(Value::as_u64),
        "bytes": file.get("bytes").and_then(Value::as_u64),
        "read_ok": file.pointer("/read/ok").and_then(Value::as_bool),
        "schema_ok": file.pointer("/read/schema_ok").and_then(Value::as_bool),
    }))
}

fn pc_use_status_proof_card_next_action(status: &str, latest_outcome: &str) -> &'static str {
    match status {
        "has_ready_runner_receipt" => {
            "Render this PC-use proof card in the right-side panel, then keep any future executor blocked until it consumes the receipt and writes its own proof."
        }
        "has_blocked_runner_receipt" if latest_outcome == "blocked_missing_queue" => {
            "Queue a PC-use payload, request the runner gate again, and keep OS-wide desktop automation blocked."
        }
        "has_blocked_runner_receipt" => {
            "Inspect the blocked runner receipt, regenerate the payload if needed, and do not hand it to a future executor."
        }
        "has_queue_without_receipt" => {
            "Request the PC-use runner gate so the queued payload has an auditable receipt before any future executor work."
        }
        _ => {
            "Compose and queue a Zed PC-use payload, then request the runner gate before any future executor work."
        }
    }
}

fn pc_use_status_next_actions(status: &str, latest_outcome: &str) -> Vec<&'static str> {
    match status {
        "has_ready_runner_receipt" => vec![
            "Send this status to the Agent Panel when the agent needs the latest PC-use gate outcome.",
            "Keep screenshots, focus, click, and type disabled until a future Zed-window executor consumes this receipt and emits its own receipt.",
        ],
        "has_blocked_runner_receipt" if latest_outcome == "blocked_missing_queue" => vec![
            "Queue a PC-use payload with queue_zed_pc_use_action_payload, then request the runner gate again.",
            "Keep OS-wide desktop automation blocked by default.",
        ],
        "has_blocked_runner_receipt" => vec![
            "Inspect the latest receipt blockers and regenerate the PC-use payload if schema or safety checks failed.",
            "Do not run future PC-use execution against a blocked receipt.",
        ],
        "has_queue_without_receipt" => vec![
            "Request the PC-use runner gate to write an auditable receipt for the latest managed queue item.",
            "Do not add a future executor until the runner-gate receipt exists.",
        ],
        _ => vec![
            "Compose and queue a Zed PC-use payload, then request the runner gate before any future executor work.",
        ],
    }
}

fn bootstrap_check(
    id: &str,
    label: &str,
    ready: bool,
    path: Option<PathBuf>,
    missing_kind: &str,
    details: &str,
) -> Value {
    serde_json::json!({
        "id": id,
        "label": label,
        "state": if ready { "ready" } else { missing_kind },
        "ready": ready,
        "path": path.as_ref().map(path_string),
        "details": details,
    })
}

fn readiness_issues(checks: &[Value], state: &str) -> Vec<Value> {
    checks
        .iter()
        .filter(|check| {
            check
                .get("state")
                .and_then(Value::as_str)
                .is_some_and(|check_state| check_state == state)
        })
        .cloned()
        .collect()
}

fn bootstrap_phase_summary(checks: &[Value]) -> Value {
    let host = bootstrap_phase("host_dependencies", checks, &["workspace.", "host."]);
    let roots = bootstrap_phase("managed_roots", checks, &["root.", "profile."]);
    let assets = bootstrap_phase("managed_assets", checks, &["asset."]);
    let ready_phase_count = [&host, &roots, &assets]
        .into_iter()
        .filter(|phase| phase.get("ready").and_then(Value::as_bool).unwrap_or(false))
        .count();

    serde_json::json!({
        "host_dependencies": host,
        "managed_roots": roots,
        "managed_assets": assets,
        "ready_phase_count": ready_phase_count,
        "total_phase_count": 3,
    })
}

fn bootstrap_phase(name: &str, checks: &[Value], prefixes: &[&str]) -> Value {
    let phase_checks = checks
        .iter()
        .filter(|check| {
            check
                .get("id")
                .and_then(Value::as_str)
                .is_some_and(|id| prefixes.iter().any(|prefix| id.starts_with(prefix)))
        })
        .cloned()
        .collect::<Vec<_>>();
    let total = phase_checks.len();
    let ready = phase_checks
        .iter()
        .filter(|check| check.get("ready").and_then(Value::as_bool).unwrap_or(false))
        .count();
    let missing = phase_checks
        .iter()
        .filter_map(|check| {
            let is_ready = check.get("ready").and_then(Value::as_bool).unwrap_or(false);
            (!is_ready)
                .then(|| check.get("id").and_then(Value::as_str).map(str::to_owned))
                .flatten()
        })
        .collect::<Vec<_>>();

    serde_json::json!({
        "name": name,
        "ready": ready == total && total > 0,
        "ready_check_count": ready,
        "total_check_count": total,
        "missing": missing,
    })
}

fn adapter_manifest_ready(path: &Path) -> bool {
    let bytes = match fs::read(path) {
        Ok(bytes) => bytes,
        Err(_) => return false,
    };
    serde_json::from_slice::<Value>(&bytes)
        .ok()
        .and_then(|value| {
            value
                .get("schema")
                .and_then(Value::as_str)
                .map(str::to_owned)
        })
        .is_some_and(|schema| schema == AGENT_CHROME_PLAYWRIGHT_ADAPTER_MANIFEST_SCHEMA)
}

fn json_file_schema(path: &Path) -> Option<String> {
    let bytes = fs::read(path).ok()?;
    serde_json::from_slice::<Value>(&bytes)
        .ok()?
        .get("schema")
        .and_then(Value::as_str)
        .map(str::to_owned)
}

fn bootstrap_next_actions(status: &str) -> Vec<&'static str> {
    match status {
        "blocked_missing_host_dependencies" => vec![
            "Install missing host dependencies first: Node.js, npm, and Chrome/Edge/Chromium.",
            "Copy or send WebPreview plugin bootstrap readiness again before provisioning.",
        ],
        "ready_to_provision" => vec![
            "Run prepare_agent_plugin_runtime with create_managed_roots=true and write_bootstrap_manifest=true to create the managed roots.",
            "Install Playwright into the managed tools root.",
            "Run prepare_managed_chrome_playwright_adapter with write_adapter_files=true.",
            "Run prepare_agent_plugin_managed_assets to write an asset receipt or copy a local unpacked DX Chrome extension into the managed agent plugin root.",
            "Keep managed Chrome profile data in the prepared profile root; never touch real user browser profiles.",
        ],
        _ => vec![
            "Chrome plugin bootstrap assets are present.",
            "Invoke the prepared Playwright adapter for safe actions, then inspect execution receipts before enabling input dispatch.",
        ],
    }
}

fn bootstrap_prepare_request(status: &str, workspace_available: bool) -> Value {
    let root_mode = if workspace_available {
        "workspace"
    } else {
        "zed_data"
    };
    let should_prepare = status == "ready_to_provision";

    serde_json::json!({
        "schema": AGENT_PLUGIN_BOOTSTRAP_PREPARE_REQUEST_SCHEMA,
        "tool_name": PREPARE_AGENT_PLUGIN_RUNTIME_TOOL,
        "readiness_status": status,
        "should_call_prepare": should_prepare,
        "authorization_required": should_prepare,
        "recommended_payload": {
            "root_mode": root_mode,
            "create_managed_roots": should_prepare,
            "write_bootstrap_manifest": should_prepare
        },
        "dry_run_payload": {
            "root_mode": root_mode,
            "create_managed_roots": false,
            "write_bootstrap_manifest": false
        },
        "blocked_by": match status {
            "blocked_missing_host_dependencies" => vec!["host_dependencies"],
            "ready_for_managed_chrome_executor" => vec!["already_prepared"],
            _ => Vec::new(),
        },
        "after_prepare_verification": {
            "tool_name": "inspect_agent_plugin_runtime_status",
            "payload": {
                "root_mode": root_mode,
                "include_host_checks": true,
                "include_bootstrap_readiness": true,
                "include_latest_handoffs": true,
                "include_next_actions": true
            }
        },
        "safety": {
            "writes_only_when_authorized": true,
            "downloads_packages": false,
            "launches_browser": false,
            "touches_real_browser_profiles": false,
            "workspace_preferred_when_available": true,
        },
    })
}

